#!/usr/bin/env node
import { createInterface } from "node:readline";
import { fileURLToPath } from "node:url";
import path from "node:path";
import process from "node:process";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type ActionChoice = "install" | "init" | "sync" | "uninstall";
type PlatformChoice = "both" | "claude" | "opencode";

interface WizardOptions {
  yes: boolean;
  command: ActionChoice | null;
  platform: PlatformChoice | null;
  targetDir: string | null;
  skipBuild: boolean;
  configPath: string | null;
}

// Minimal types for the mjs lib functions used by this wizard
interface ParsedOptions {
  command: string;
  tool: string;
  configPath: string | null;
  skipBuild: boolean;
  platform: string;
  targetDir: string;
  help: boolean;
}

interface ProjectConfig {
  path: string;
  exists: boolean;
  value: Record<string, unknown>;
}

interface Manifest {
  version: number;
  packageName: string;
  adapters: Record<string, unknown>;
}

interface AdapterSelection {
  claude: boolean;
  opencode: boolean;
}

interface ScaffoldSelection {
  plans: boolean;
  vault: boolean;
}

interface HelpersLib {
  parseArgs: (argv: string[], options?: { forcedTool?: string | null }) => ParsedOptions;
  ensureTargetDir: (targetDir: string) => void;
  getPackageName: () => string;
  loadProjectConfig: (options: ParsedOptions) => ProjectConfig;
  readManifest: (targetDir: string) => Manifest;
  writeManifest: (targetDir: string, manifest: Manifest) => void;
  resolveAdapterSelection: (options: ParsedOptions, config: Record<string, unknown>, manifest: Manifest) => AdapterSelection;
  resolveScaffoldSelection: (options: ParsedOptions, config: Record<string, unknown>) => ScaffoldSelection;
  seedIndexConfig: (config: ProjectConfig) => void;
  scaffoldProject: (targetDir: string, scaffold: ScaffoldSelection) => void;
  isInstalledPackage: () => boolean;
  run: (command: string, args: string[]) => void;
  log: (message: string) => void;
}

interface ClaudeAdapterState {
  commands: string[];
  settingsPath: string;
  mcpConfigPath: string;
  generatedPaths: string[];
  managedDirectories: string[];
}

interface ClaudeLib {
  installClaude: (platform: string, targetDir: string, packageName: string) => ClaudeAdapterState;
  uninstallClaude: (targetDir: string, claudeState: unknown) => boolean;
}

interface OpencodeAdapterState {
  generatedPaths: string[];
  managedDirectories: string[];
}

interface OpencodeLib {
  installOpenCode: (targetDir: string, packageName: string) => OpencodeAdapterState;
  uninstallOpenCode: (targetDir: string, opencodeState: unknown) => boolean;
  runAssetSync: (options: ParsedOptions, adapters: AdapterSelection) => void;
}

interface InstallContext {
  helpers: HelpersLib;
  claudeLib: ClaudeLib;
  opencodeLib: OpencodeLib;
  options: ParsedOptions;
  manifest: Manifest;
  adapters: AdapterSelection;
  packageName: string;
}

// ---------------------------------------------------------------------------
// Path resolution: dist/src/bin/hf-setup.js 竊・project root is ../../../
// ---------------------------------------------------------------------------

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
// When compiled: dist/src/bin/hf-setup.js 竊・go up 3 levels to reach project root
const projectRoot = path.resolve(__dirname, "..", "..", "..");
const libDir = path.join(projectRoot, "scripts", "lib");

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

function parseArgs(argv: string[]): WizardOptions {
  const options: WizardOptions = {
    yes: false,
    command: null,
    platform: null,
    targetDir: null,
    skipBuild: false,
    configPath: null
  };

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i];

    if (arg === "--yes" || arg === "-y") {
      options.yes = true;
      continue;
    }

    if (arg === "--skip-build") {
      options.skipBuild = true;
      continue;
    }

    if ((arg === "--command" || arg === "-c") && argv[i + 1] !== undefined) {
      const val = argv[i + 1] as string;
      if (!["install", "init", "sync", "uninstall"].includes(val)) {
        throw new Error(`Unsupported --command value: ${val}. Must be one of: install, init, sync, uninstall`);
      }
      options.command = val as ActionChoice;
      i++;
      continue;
    }

    if (arg === "--platform" && argv[i + 1] !== undefined) {
      const val = argv[i + 1] as string;
      if (!["both", "claude", "opencode"].includes(val)) {
        throw new Error(`Unsupported --platform value: ${val}. Must be one of: both, claude, opencode`);
      }
      options.platform = val as PlatformChoice;
      i++;
      continue;
    }

    if (arg === "--target-dir" && argv[i + 1] !== undefined) {
      options.targetDir = path.resolve(argv[i + 1] as string);
      i++;
      continue;
    }

    if (arg === "--config" && argv[i + 1] !== undefined) {
      options.configPath = path.resolve(argv[i + 1] as string);
      i++;
    }
  }

  return options;
}

// ---------------------------------------------------------------------------
// Readline prompt helpers (stderr for prompts so stdout stays clean)
// ---------------------------------------------------------------------------

function prompt(rl: ReturnType<typeof createInterface>, question: string): Promise<string> {
  return new Promise((resolve) => {
    rl.question(question, (answer) => resolve(answer.trim()));
  });
}

async function askAction(rl: ReturnType<typeof createInterface>): Promise<ActionChoice> {
  process.stderr.write("\nSelect action:\n");
  process.stderr.write("  1) Install   窶・first-time wiring\n");
  process.stderr.write("  2) Init      窶・scaffold + wiring\n");
  process.stderr.write("  3) Sync      窶・refresh existing wiring\n");
  process.stderr.write("  4) Uninstall 窶・remove wiring\n");

  const answer = await prompt(rl, "Choice [1-4] (default: 1): ");
  const map: Record<string, ActionChoice> = {
    "": "install",
    "1": "install",
    "2": "init",
    "3": "sync",
    "4": "uninstall",
    install: "install",
    init: "init",
    sync: "sync",
    uninstall: "uninstall"
  };

  const choice = map[answer];
  if (choice === undefined) {
    throw new Error(`Invalid choice: "${answer}". Enter 1-4 or a command name.`);
  }
  return choice;
}

async function askPlatform(rl: ReturnType<typeof createInterface>): Promise<PlatformChoice> {
  process.stderr.write("\nSelect platform:\n");
  process.stderr.write("  1) Both         窶・Claude + OpenCode\n");
  process.stderr.write("  2) Claude only\n");
  process.stderr.write("  3) OpenCode only\n");

  const answer = await prompt(rl, "Choice [1-3] (default: 1): ");
  const map: Record<string, PlatformChoice> = {
    "": "both",
    "1": "both",
    "2": "claude",
    "3": "opencode",
    both: "both",
    claude: "claude",
    opencode: "opencode"
  };

  const choice = map[answer];
  if (choice === undefined) {
    throw new Error(`Invalid choice: "${answer}". Enter 1-3 or a platform name.`);
  }
  return choice;
}

// ---------------------------------------------------------------------------
// Execute helpers 窶・lifted to module level with explicit InstallContext param
// ---------------------------------------------------------------------------

function executeInstall(commandLabel: string, ctx: InstallContext): void {
  const nextManifest: Manifest = {
    version: 1,
    packageName: ctx.packageName,
    adapters: {
      ...ctx.manifest.adapters
    }
  };

  ctx.opencodeLib.runAssetSync(ctx.options, ctx.adapters);

  if (ctx.adapters.claude) {
    nextManifest.adapters["claude"] = ctx.claudeLib.installClaude(
      ctx.options.platform,
      ctx.options.targetDir,
      ctx.packageName
    );
  }

  if (ctx.adapters.opencode) {
    nextManifest.adapters["opencode"] = ctx.opencodeLib.installOpenCode(
      ctx.options.targetDir,
      ctx.packageName
    );
  }

  ctx.helpers.writeManifest(ctx.options.targetDir, nextManifest);
  ctx.helpers.log(`Hybrid runtime ${commandLabel} complete.`);
}

function executeUninstall(ctx: InstallContext): void {
  const nextManifest: Manifest = {
    ...ctx.manifest,
    adapters: {
      ...ctx.manifest.adapters
    }
  };

  if (ctx.adapters.claude) {
    ctx.claudeLib.uninstallClaude(ctx.options.targetDir, ctx.manifest.adapters["claude"]);
    delete nextManifest.adapters["claude"];
  }

  if (ctx.adapters.opencode) {
    ctx.opencodeLib.uninstallOpenCode(ctx.options.targetDir, ctx.manifest.adapters["opencode"]);
    delete nextManifest.adapters["opencode"];
  }

  ctx.helpers.writeManifest(ctx.options.targetDir, nextManifest);
  ctx.helpers.log("Hybrid runtime uninstall complete.");
}

// ---------------------------------------------------------------------------
// Context builder 窶・loads libs and resolves parsed options + selections
// ---------------------------------------------------------------------------

interface SetupContext {
  ctx: InstallContext;
  config: ProjectConfig;
  scaffold: ScaffoldSelection;
  shouldScaffold: boolean;
}

async function buildSetupContext(
  command: ActionChoice,
  platform: PlatformChoice,
  opts: WizardOptions
): Promise<SetupContext> {
  // Dynamic imports of mjs lib files 窶・resolved via file:// URL so Node ESM resolves correctly
  const helpers = (await import(`file://${path.join(libDir, "install-helpers.mjs")}`)) as HelpersLib;
  const claudeLib = (await import(`file://${path.join(libDir, "install-claude.mjs")}`)) as ClaudeLib;
  const opencodeLib = (await import(`file://${path.join(libDir, "install-opencode.mjs")}`)) as OpencodeLib;

  const toolMap: Record<PlatformChoice, string> = { both: "all", claude: "claude", opencode: "opencode" };

  const cliBits: string[] = [command, "--tool", toolMap[platform]];
  if (opts.targetDir !== null) cliBits.push("--target-dir", opts.targetDir);
  if (opts.skipBuild) cliBits.push("--skip-build");
  if (opts.configPath !== null) cliBits.push("--config", opts.configPath);

  const options = helpers.parseArgs(cliBits);
  helpers.ensureTargetDir(options.targetDir);

  const packageName = helpers.getPackageName();
  const config = helpers.loadProjectConfig(options);
  const manifest = helpers.readManifest(options.targetDir);
  const adapters = helpers.resolveAdapterSelection(options, config.value, manifest);
  const scaffold = helpers.resolveScaffoldSelection(options, config.value);
  const shouldScaffold = command === "init" && (scaffold.plans || scaffold.vault);
  const ctx: InstallContext = { helpers, claudeLib, opencodeLib, options, manifest, adapters, packageName };

  return { ctx, config, scaffold, shouldScaffold };
}

// ---------------------------------------------------------------------------
// Setup orchestration 窶・replicates install-runtime.mjs logic via lib imports
// ---------------------------------------------------------------------------

async function runSetup(command: ActionChoice, platform: PlatformChoice, opts: WizardOptions): Promise<void> {
  const { ctx, config, scaffold, shouldScaffold } = await buildSetupContext(command, platform, opts);
  const { helpers, adapters, options } = ctx;

  if (!adapters.claude && !adapters.opencode && command !== "uninstall" && !shouldScaffold) {
    helpers.log(`No adapters are enabled for ${command}.`);
    if (config.exists) {
      helpers.log(`Config checked: ${path.relative(options.targetDir, config.path)}`);
    }
    return;
  }

  if (
    (command === "install" || command === "init") &&
    !options.skipBuild &&
    !helpers.isInstalledPackage() &&
    (adapters.claude || adapters.opencode)
  ) {
    helpers.run("npm", ["install"]);
    helpers.run("npm", ["run", "build"]);
  }

  if (command === "install") { executeInstall("install", ctx); return; }
  if (command === "sync") { executeInstall("sync", ctx); return; }
  if (command === "uninstall") { executeUninstall(ctx); return; }

  helpers.seedIndexConfig(config);
  helpers.scaffoldProject(options.targetDir, scaffold);
  executeInstall("install", ctx);
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  const argv = process.argv.slice(2);
  const opts = parseArgs(argv);

  // Non-interactive: --yes uses defaults; both --command and --platform supplied skips prompts
  const nonInteractive = opts.yes || (opts.command !== null && opts.platform !== null);

  let command: ActionChoice;
  let platform: PlatformChoice;

  if (nonInteractive) {
    command = opts.command ?? "install";
    platform = opts.platform ?? "both";
    process.stderr.write(`Running hf-setup: command=${command}, platform=${platform}\n`);
  } else {
    const rl = createInterface({ input: process.stdin, output: process.stderr });

    try {
      command = opts.command ?? (await askAction(rl));
      platform = opts.platform ?? (await askPlatform(rl));
    } finally {
      rl.close();
    }

    process.stderr.write(`\nRunning: ${command} / ${platform}...\n`);
  }

  await runSetup(command, platform, opts);
  process.stderr.write("Done.\n");
}

main().catch((error: unknown) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exitCode = 1;
});

import {
  hydrateRuntimeWithTimeout,
  ingestTurnOutcome,
  isDestructiveCommand,
  isProtectedConfigEdit,
  recordCompactionArchive,
  recordSubagentLifecycle
} from "../adapters/lifecycle.js";
import type { HybridLoopRuntime } from "../runtime/runtime.js";
import { detectTurnOutcomeInPayload } from "../runtime/turn-outcome-ingestion.js";
import { hfLog, hfLogTimed } from "../runtime/logger.js";
import type { ContinueDecision, RuntimeEvent } from "../runtime/types.js";

const HOOK_SPECIFIC_OUTPUT_KEY = "hookSpecificOutput";

export function mapDecisionToClaudeStopResponse(decision: ContinueDecision): Record<string, unknown> {
  switch (decision.action) {
    case "continue":
      return {
        decision: "block",
        reason: `${decision.reason} Continue with: ${decision.resume_prompt ?? "follow the current milestone"}`
      };
    case "allow_stop":
    case "pause":
    case "escalate":
    case "complete":
    case "max_turns":
      return {
        decision: "allow",
        reason: decision.reason
      };
  }
}

const HOOK_TIMEOUT_MS = 4_000;
const HOOK_LOG_TAG = "claude-hook";

export interface ClaudeHookInput {
  session_id?: string;
  tool_name?: string;
  message?: string;
  metadata?: Record<string, unknown>;
  tool_input?: {
    command?: string;
    file_path?: string;
    filePath?: string;
  };
}

export function toRuntimeEvent(eventName: string, input: ClaudeHookInput): RuntimeEvent {
  const payload = input.metadata ?? (input.tool_name ? { tool_name: input.tool_name } : undefined);

  return {
    vendor: "claude",
    type: `claude.${eventName}`,
    timestamp: new Date().toISOString(),
    ...(input.session_id ? { sessionId: input.session_id } : {}),
    ...(payload ? { payload } : {})
  };
}

function handlePreToolUse(
  eventName: string,
  input: ClaudeHookInput
): Record<string, unknown> | null {
  if (input.tool_name === "Bash") {
    const command = String(input.tool_input?.command ?? input.metadata?.command ?? "");
    if (isDestructiveCommand(command)) {
      return {
        [HOOK_SPECIFIC_OUTPUT_KEY]: {
          hookEventName: eventName,
          permissionDecision: "deny",
          permissionDecisionReason: "Hybrid runtime guardrail blocked a destructive command."
        }
      };
    }
  }
  const writeEditTools = new Set(["Write", "Edit", "MultiEdit", "FileEdit"]);
  if (writeEditTools.has(input.tool_name ?? "")) {
    const filePath = String(input.tool_input?.file_path ?? input.metadata?.file_path ?? "");
    if (filePath && isProtectedConfigEdit(filePath)) {
      return {
        [HOOK_SPECIFIC_OUTPUT_KEY]: {
          hookEventName: eventName,
          permissionDecision: "deny",
          permissionDecisionReason: `Hybrid runtime guardrail blocked an edit to protected config file: ${filePath}. Set HF_ALLOW_CONFIG_EDIT=1 to allow intentional changes.`
        }
      };
    }
  }
  return null;
}

async function handleSessionOrPrompt(
  runtime: HybridLoopRuntime,
  eventName: string
): Promise<Record<string, unknown>> {
  const decision = await runtime.decideNext();
  hfLog({ tag: HOOK_LOG_TAG, msg: `${eventName} decision`, data: { action: decision.action } });
  return {
    [HOOK_SPECIFIC_OUTPUT_KEY]: {
      hookEventName: eventName,
      additionalContext: decision.resume_prompt
    }
  };
}

async function handlePreCompact(
  runtime: HybridLoopRuntime,
  eventName: string,
  input: ClaudeHookInput
): Promise<Record<string, unknown>> {
  const decision = await runtime.decideNext();
  await recordCompactionArchive(runtime, {
    vendor: "claude",
    eventType: "claude.pre_compact_archive",
    ...(input.session_id ? { sessionId: input.session_id } : {})
  });
  return {
    [HOOK_SPECIFIC_OUTPUT_KEY]: {
      hookEventName: eventName,
      additionalContext: decision.resume_prompt
    }
  };
}

function resolveSubagentStatus(
  eventName: string,
  input: ClaudeHookInput
): "running" | "completed" | "failed" {
  if (eventName === "SubagentStart") {
    return "running";
  }
  if (input.metadata?.error !== undefined) {
    return "failed";
  }
  return "completed";
}

async function handleSubagentEvent(
  runtime: HybridLoopRuntime,
  eventName: string,
  input: ClaudeHookInput
): Promise<Record<string, unknown>> {
  const subagentId = String(input.metadata?.subagent_id ?? input.session_id ?? "unknown");
  const subagentName = String(input.metadata?.subagent_name ?? input.tool_name ?? "unnamed");
  await recordSubagentLifecycle(runtime, {
    id: subagentId,
    name: subagentName,
    status: resolveSubagentStatus(eventName, input)
  });
  return { decision: "allow" };
}

async function handleStop(
  runtime: HybridLoopRuntime,
  eventName: string,
  input: ClaudeHookInput
): Promise<Record<string, unknown>> {
  if (runtime.isPlanless()) {
    await runtime.recordEvent(toRuntimeEvent(eventName, input));
    const decision = await runtime.decideNext();
    return mapDecisionToClaudeStopResponse(decision);
  }

  const detection = detectTurnOutcomeInPayload(input, "claude hook input");
  await ingestTurnOutcome(runtime, {
    vendor: "claude",
    source: detection.source,
    result: detection.result,
    ...(input.session_id ? { sessionId: input.session_id } : {}),
    countMissingAsAttempt: true
  });

  const decision = await runtime.decideNext();
  return mapDecisionToClaudeStopResponse(decision);
}

async function hydrateOrTimeout(
  opts: { cwd: string; explicitPlanPath?: string },
  eventName: string
): Promise<HybridLoopRuntime | null> {
  try {
    return await hydrateRuntimeWithTimeout({
      cwd: opts.cwd,
      timeoutMs: HOOK_TIMEOUT_MS,
      timeoutMessage: "Hook hydration timed out",
      tag: HOOK_LOG_TAG,
      ...(opts.explicitPlanPath ? { explicitPlanPath: opts.explicitPlanPath } : {})
    });
  } catch (error) {
    if (!(error instanceof Error && error.message === "Hook hydration timed out")) {
      throw error;
    }
    hfLog({ tag: HOOK_LOG_TAG, msg: "hydration timed out", data: { eventName } });
    return null;
  }
}

export async function handleClaudeHook(
  eventName: string,
  input: ClaudeHookInput,
  opts: { cwd: string; explicitPlanPath?: string }
): Promise<Record<string, unknown>> {
  const hookDone = hfLogTimed({ tag: HOOK_LOG_TAG, msg: `handleClaudeHook(${eventName})` });

  if (eventName === "PostToolUse" || eventName === "Notification") {
    hookDone({ shortCircuit: true });
    return { decision: "allow" };
  }

  if (eventName === "PreToolUse") {
    const denied = handlePreToolUse(eventName, input);
    if (denied) { hookDone({ blocked: true }); return denied; }
    hookDone({ shortCircuit: true });
    return { decision: "allow" };
  }

  const runtime = await hydrateOrTimeout(opts, eventName);
  if (!runtime) {
    const isContextEvent = eventName === "SessionStart" || eventName === "UserPromptSubmit" || eventName === "PreCompact";
    return isContextEvent ? { [HOOK_SPECIFIC_OUTPUT_KEY]: { hookEventName: eventName } } : { decision: "allow" };
  }

  if (eventName !== "Stop") {
    await runtime.recordEvent(toRuntimeEvent(eventName, input));
  }

  if (eventName === "SessionStart" || eventName === "UserPromptSubmit") {
    const result = await handleSessionOrPrompt(runtime, eventName);
    hookDone({ action: eventName });
    return result;
  }
  if (eventName === "PreCompact") {
    const result = await handlePreCompact(runtime, eventName, input);
    hookDone({ action: eventName });
    return result;
  }
  if (eventName === "SubagentStart" || eventName === "SubagentStop") {
    return handleSubagentEvent(runtime, eventName, input);
  }
  if (eventName === "Stop") {
    const result = await handleStop(runtime, eventName, input);
    hookDone({ action: (result).decision });
    return result;
  }

  hookDone({ fallthrough: true });
  return { decision: "allow" };
}

import path from "node:path";
import { promises as fs } from "node:fs";
import { createRequire } from "node:module";

import { hydrateRuntimeWithTimeout } from "../adapters/lifecycle.js";
import type { HybridLoopRuntime } from "../runtime/runtime.js";
import { parsePlan } from "../runtime/plan-doc.js";
import { hfLog } from "../runtime/logger.js";
import { formatToolSearchResults } from "../runtime/prompt.js";
import {
  type ToolContext,
  type OpenCodePluginContext
} from "./plugin-utils.js";
import type { SessionManager } from "./plugin-session.js";

const ALL_COMPLETE_LABEL = "(all complete)";

/**
 * Lazily load `z` from the bundled zod that ships with @opencode-ai/plugin.
 *
 * The plugin package lives in .opencode/node_modules/ which is NOT on the
 * normal Node resolution path, so we cannot add it as a compile-time dep.
 * We use createRequire + the zod CJS entry to get a synchronous handle on z.
 *
 * The .opencode/node_modules/zod package ships both ESM (index.js) and CJS
 * (index.cjs); we target the CJS file so that createRequire works regardless
 * of the host module format.  The exported object shape is { z, core, ... }
 * so we pull `.z` off it.
 */
const _req = createRequire(import.meta.url);
 
const _zodMod = _req(
  path.resolve(process.cwd(), ".opencode", "node_modules", "zod", "index.cjs")
) as {
  z: {
    string(): { describe(s: string): { optional(): unknown } };
    number(): { describe(s: string): { optional(): unknown } };
  }
};
// pluginZ is the `z` export 窶・used only to build the hf_plan_start args schema.
const pluginZ = _zodMod.z;

const SEARCH_TIMEOUT_MS = 15_000;

type SearchArgs = { query: string; top_k?: number; source?: string };

async function listAvailablePlans(baseDir: string): Promise<string[]> {
  const plansDir = path.join(baseDir, "plans");
  try {
    const entries = await fs.readdir(plansDir);
    return entries
      .filter((name) => name.endsWith("-plan.md"))
      .map((name) => `plans/${name}`);
  } catch {
    return [];
  }
}

async function resolvePlanPath(planArg: string, baseDir: string): Promise<string> {
  if (planArg.includes("/") || planArg.includes("\\") || planArg.endsWith(".md")) {
    const resolved = path.resolve(baseDir, planArg);
    try {
      await fs.access(resolved);
    } catch {
      const available = await listAvailablePlans(baseDir);
      const listStr = available.length > 0
        ? available.map((p) => `  - ${p}`).join("\n")
        : "  (no plans found)";
      throw new Error(`Plan file not found: ${planArg}\n\nAvailable plans:\n${listStr}`);
    }
    return resolved;
  }

  const plansDir = path.join(baseDir, "plans");
  let entries: string[] = [];
  try {
    entries = await fs.readdir(plansDir);
  } catch {
    throw new Error(`Could not read plans/ directory at ${plansDir}. Make sure you are running from the project root.`);
  }

  const candidates = entries.filter((name) => {
    const lower = name.toLowerCase();
    return lower.includes(planArg.toLowerCase()) && lower.endsWith("-plan.md");
  });

  if (candidates.length === 0) {
    const allPlans = entries.filter((name) => name.endsWith("-plan.md"));
    const listStr = allPlans.length > 0
      ? allPlans.map((p) => `  - plans/${p}`).join("\n")
      : "  (no plan files found in plans/)";
    throw new Error(`No plan found matching "${planArg}".\n\nAvailable plans:\n${listStr}`);
  }

  if (candidates.length > 1) {
    const listStr = candidates.map((p) => `  - plans/${p}`).join("\n");
    throw new Error(`Ambiguous plan slug "${planArg}" 窶・matches ${candidates.length} files. Be more specific:\n${listStr}`);
  }

  return path.join(plansDir, candidates[0]!);
}

async function buildPlanSummary(resolvedPath: string, manager: SessionManager, sessionId: string): Promise<string> {
  const runtime = await manager.getRuntime(sessionId);
  if (!runtime || runtime.isPlanless()) {
    return `Plan bound: ${resolvedPath}\n(Runtime hydration returned planless or null 窶・check plan doc format.)`;
  }

  const status = runtime.getStatus();
  try {
    const parsed = await parsePlan(resolvedPath);
    const planTitle =
      parsed.milestones.length > 0 && parsed.userIntent
        ? (parsed.userIntent.split("\n")[0]?.trim() ?? path.basename(resolvedPath))
        : path.basename(resolvedPath);
    const totalMilestones = parsed.milestones.length;
    const currentIdx = parsed.currentMilestone?.index ?? null;
    const currentTitle = parsed.currentMilestone?.title ?? ALL_COMPLETE_LABEL;
    const currentMilestoneLabel = currentIdx === null ? ALL_COMPLETE_LABEL : `M${currentIdx} 窶・${currentTitle}`;
    return [
      `Plan bound: ${resolvedPath}`,
      `Title: ${planTitle}`,
      `Status: ${parsed.status}`,
      `Loop state: ${status.loopState}`,
      `Current milestone: ${currentMilestoneLabel}`,
      `Total milestones: ${totalMilestones} (${parsed.milestones.filter((m) => m.checked).length} complete)`
    ].join("\n");
  } catch {
    return [
      `Plan bound: ${resolvedPath}`,
      `Loop state: ${status.loopState}`
    ].join("\n");
  }
}

type SearchParams = { cwd: string; sessionId: string; getRuntime: (id: string) => Promise<HybridLoopRuntime | null> };

async function executeSearchQuery(
  args: SearchArgs,
  params: SearchParams
): Promise<string> {
  const query = args.query;
  const topK = args.top_k;
  const sourceArg = args.source;
  let sourceFilter: "vault" | "code" | undefined;
  if (sourceArg === "vault") sourceFilter = "vault";
  else if (sourceArg === "code") sourceFilter = "code";

  let runtime = await params.getRuntime(params.sessionId);

  if (!runtime) {
    try {
      runtime = await hydrateRuntimeWithTimeout({
        cwd: params.cwd,
        timeoutMs: SEARCH_TIMEOUT_MS,
        timeoutMessage: "Runtime hydration timed out",
        tag: "plugin/hf_search",
      });
    } catch (err) {
      return `Index build failed: ${String(err instanceof Error ? err.message : err)}. Try again or check the runtime logs.`;
    }
  }

  const results = await runtime.queryIndex(query, topK, sourceFilter);
  if (results === null) {
    return "No index available 窶・the on-demand index build returned no results. Try again or check the runtime logs.";
  }
  return formatToolSearchResults(results);
}

type PlanCompleteArgs = { plan?: string; summary?: string };
type BindingRequest = { planArg: string; sessionId: string; directory: string };

async function resolvePlanCompleteBinding(
  req: BindingRequest,
  manager: SessionManager
): Promise<{ resolvedPath: string } | { error: string }> {
  const { planArg, sessionId, directory } = req;
  if (planArg) {
    let resolvedPath: string;
    try {
      resolvedPath = await resolvePlanPath(planArg, directory);
    } catch (err) {
      return { error: String(err instanceof Error ? err.message : err) };
    }
    manager.planBindings.set(sessionId, resolvedPath);
    manager.sessionRuntimes.delete(sessionId);
    const orderIdx = manager.sessionAccessOrder.indexOf(sessionId);
    if (orderIdx !== -1) manager.sessionAccessOrder.splice(orderIdx, 1);
    return { resolvedPath };
  }
  const bound = manager.planBindings.get(sessionId);
  if (!bound) {
    return { error: "No plan is bound to this session. Call hf_plan_start first, or pass an explicit plan slug." };
  }
  return { resolvedPath: bound };
}

type OutcomeParams = { resolvedPath: string; summary: string; sessionId: string };

async function evaluatePlanCompleteOutcome(params: OutcomeParams, runtime: HybridLoopRuntime): Promise<string> {
  const { resolvedPath, summary, sessionId } = params;
  let parsed: Awaited<ReturnType<typeof parsePlan>>;
  try {
    parsed = await parsePlan(resolvedPath);
  } catch (err) {
    return `Error: Could not parse plan doc: ${String(err)}`;
  }
  if (!parsed.completed) {
    const unchecked = parsed.milestones.filter((m) => !m.checked);
    const list = unchecked.map((m) => `  - M${m.index}: ${m.title}`).join("\n");
    return [`Error: Plan is not complete 窶・${unchecked.length} milestone(s) are still unchecked.`, list, "", "Check all milestones and update the frontmatter to `status: complete` before calling hf_plan_complete."].join("\n");
  }
  const outcome = { state: "plan_complete" as const, summary: summary || `All milestones complete for plan: ${parsed.slug}`, files_changed: [] as string[], tests_run: [] as never[], next_action: "Plan loop closed." };
  let status: Awaited<ReturnType<typeof runtime.evaluateTurn>>;
  try {
    status = await runtime.evaluateTurn(outcome);
  } catch (err) {
    return `Error: evaluateTurn failed: ${String(err)}`;
  }
  hfLog({ tag: "plugin", msg: "hf_plan_complete: loop closed", data: { sessionId, resolvedPath, loopState: status.loopState } });
  return [`Plan loop closed: ${resolvedPath}`, `Loop state: ${status.loopState}`, `Plan slug: ${status.planSlug}`, `Total milestones: ${parsed.milestones.length} ${ALL_COMPLETE_LABEL}`].join("\n");
}

async function executePlanComplete(args: PlanCompleteArgs, toolContext: ToolContext, manager: SessionManager): Promise<string> {
  const sessionId = toolContext.sessionID;
  const planArg = (args.plan ?? "").trim();
  const bindResult = await resolvePlanCompleteBinding({ planArg, sessionId, directory: toolContext.directory }, manager);
  if ("error" in bindResult) return `Error: ${bindResult.error}`;
  const { resolvedPath } = bindResult;

  let runtime: HybridLoopRuntime | null;
  try {
    runtime = await manager.getRuntime(sessionId);
  } catch (err) {
    return `Error: Runtime hydration failed: ${String(err)}`;
  }
  if (!runtime || runtime.isPlanless()) {
    return `Error: Runtime is not bound to a plan (got planless or null). Make sure the plan doc has a ## Milestones section.`;
  }
  return evaluatePlanCompleteOutcome({ resolvedPath, summary: (args.summary ?? "").trim(), sessionId }, runtime);
}

function buildPlanStartTool(manager: SessionManager) {
  const { planBindings, sessionRuntimes, sessionAccessOrder } = manager;
  return {
    description: "Bind this OpenCode session to a specific hybrid-framework plan doc. Call this at the start of every builder or planner session before running any plan milestones. Pass a plan slug (e.g. 'my-feature') or a relative path (e.g. 'plans/2026-03-27-my-feature-plan.md').",
    args: { plan: pluginZ.string().describe("Plan slug or relative path (e.g. 'my-feature' or 'plans/2026-03-27-my-feature-plan.md')") },
    execute: async (args: { plan: string }, toolContext: ToolContext): Promise<string> => {
      const planArg = args.plan;
      let resolvedPath: string;
      try {
        resolvedPath = await resolvePlanPath(planArg, toolContext.directory);
      } catch (err) {
        return `Error: ${String(err instanceof Error ? err.message : err)}`;
      }
      const sessionId = toolContext.sessionID;
      planBindings.set(sessionId, resolvedPath);
      sessionRuntimes.delete(sessionId);
      const orderIdx = sessionAccessOrder.indexOf(sessionId);
      if (orderIdx !== -1) sessionAccessOrder.splice(orderIdx, 1);
      hfLog({ tag: "plugin", msg: "hf_plan_start: plan bound", data: { sessionId, resolvedPath } });
      try {
        return await buildPlanSummary(resolvedPath, manager, sessionId);
      } catch (err) {
        return `Plan bound: ${resolvedPath}\n(Warning: runtime hydration failed: ${String(err)})`;
      }
    }
  };
}

function buildSearchTool(context: OpenCodePluginContext, manager: SessionManager) {
  return {
    description: "Search the hybrid framework's unified semantic index (vault docs, code, and external files). Optionally filter by source: 'vault' for documentation, 'code' for source code, 'all' (default) for everything.",
    args: {
      query: pluginZ.string().describe("Natural language search query"),
      top_k: pluginZ.number().describe("Number of results to return (default: 5)").optional(),
      source: pluginZ.string().describe("Source filter: 'vault' for documentation only, 'code' for source code only, 'all' for everything (default: 'all')").optional()
    },
    execute: async (args: SearchArgs, toolContext: ToolContext): Promise<string> => {
      try {
        return await executeSearchQuery(args, { cwd: context.cwd ?? toolContext.directory, sessionId: toolContext.sessionID, getRuntime: manager.getRuntime });
      } catch (err) {
        return `Error querying index: ${String(err)}`;
      }
    }
  };
}

function buildPlanCompleteTool(manager: SessionManager) {
  return {
    description: "Close the hybrid-framework plan loop after all milestones are checked and status is set to complete. Call this as the final step of every builder session once the plan doc frontmatter has been updated to `status: complete`. Accepts an optional plan slug or path; defaults to the currently bound plan.",
    args: {
      plan: pluginZ.string().describe("Plan slug or relative path (e.g. 'my-feature' or 'plans/2026-03-27-my-feature-plan.md'). Omit to use the currently bound plan.").optional(),
      summary: pluginZ.string().describe("One-sentence summary of what was accomplished across all milestones.").optional(),
    },
    execute: (args: PlanCompleteArgs, toolContext: ToolContext) =>
      executePlanComplete(args, toolContext, manager)
  };
}

function buildPlanStatusTool(manager: SessionManager) {
  return {
    description: "Show the active plan binding and current plan state for this session. Call this at the start of any session to confirm you are working on the correct plan before executing milestones.",
    args: {},
    execute: async (_args: Record<string, never>, toolContext: ToolContext): Promise<string> => {
      const sessionId = toolContext.sessionID;
      const resolvedPath = manager.planBindings.get(sessionId);
      if (!resolvedPath) {
        return "No plan is bound to this session. Call hf_plan_start to bind one.";
      }
      return buildPlanSummary(resolvedPath, manager, sessionId);
    }
  };
}

const PLAN_LIST_TIMEOUT_MS = 200;

function buildPlanListTool(manager: SessionManager) {
  return {
    description: "List all active plan bindings across all sessions in this process. Use this to diagnose cross-session plan confusion when multiple sessions are running simultaneously.",
    args: {},
    execute: async (_args: Record<string, never>): Promise<string> => {
      const { planBindings, sessionRuntimes } = manager;
      if (planBindings.size === 0) {
        return "No active plan bindings in this process.";
      }
      const lines: string[] = [`Active plan bindings (${planBindings.size} sessions):`];
      for (const [sessionId, resolvedPath] of planBindings) {
        const filename = path.basename(resolvedPath);
        const loopState = await resolveLoopState(sessionRuntimes, sessionId);
        lines.push(`  session ${sessionId} 竊・plans/${filename} (loopState: ${loopState})`);
      }
      return lines.join("\n");
    }
  };
}

async function resolveLoopState(
  sessionRuntimes: Map<string, Promise<HybridLoopRuntime | null>>,
  sessionId: string
): Promise<string> {
  const runtimePromise = sessionRuntimes.get(sessionId);
  if (!runtimePromise) return "not hydrated";
  const timeout = new Promise<null>((resolve) => setTimeout(() => resolve(null), PLAN_LIST_TIMEOUT_MS));
  const result = await Promise.race([runtimePromise, timeout]);
  if (!result) return "not hydrated";
  if (result.isPlanless()) return "planless";
  return result.getStatus().loopState;
}

function buildPlanUnbindTool(manager: SessionManager) {
  return {
    description: "Remove the active plan binding from this session without completing the plan loop. Use when pivoting to a different task or when the session should become planless. The plan doc is not modified.",
    args: {},
    execute: (_args: Record<string, never>, toolContext: ToolContext): string => {
      const sessionId = toolContext.sessionID;
      const resolvedPath = manager.planBindings.get(sessionId);
      if (!resolvedPath) {
        return "No plan is bound to this session 窶・nothing to unbind.";
      }
      manager.planBindings.delete(sessionId);
      manager.sessionRuntimes.delete(sessionId);
      const orderIdx = manager.sessionAccessOrder.indexOf(sessionId);
      if (orderIdx !== -1) manager.sessionAccessOrder.splice(orderIdx, 1);
      hfLog({ tag: "plugin", msg: "hf_plan_unbind: binding removed", data: { sessionId, resolvedPath } });
      return `Plan unbound: ${resolvedPath}\nThis session is now planless. Call hf_plan_start to bind a new plan.`;
    }
  };
}

function formatMilestoneLabel(milestone: { index: number; title: string } | null): string {
  if (milestone === null) return ALL_COMPLETE_LABEL;
  return `M${milestone.index} 窶・${milestone.title}`;
}

function formatLastVerification(
  lastVerification: { status: "pass" | "fail" | "unknown"; summary?: string; at: string } | undefined
): string {
  if (!lastVerification) return "none";
  return `${lastVerification.status} 窶・${lastVerification.summary ?? ""}`;
}

function buildRuntimeStatusTool(manager: SessionManager) {
  return {
    description: "Show live loop counters, phase, and recommended next action for the plan bound to this session. Use this to inspect runtime state before thresholds are crossed and escalation is triggered.",
    args: {},
    execute: async (_args: Record<string, never>, toolContext: ToolContext): Promise<string> => {
      const sessionId = toolContext.sessionID;
      if (!manager.planBindings.get(sessionId)) {
        return "No plan is bound to this session. Call hf_plan_start to bind one before checking runtime status.";
      }
      const runtime = await manager.getRuntime(sessionId);
      if (!runtime || runtime.isPlanless()) {
        return "Runtime not yet initialized for this session.";
      }
      const status = runtime.getStatus();
      const { counters } = status;
      const planLabel = `plans/${path.basename(status.planPath)}`;
      const milestoneLabel = formatMilestoneLabel(status.currentMilestone);
      const nextAction = status.recommendedNextAction ?? "none";
      const lastBlocker = status.lastBlocker?.message ?? "none";
      const lastVerification = formatLastVerification(status.lastVerification);
      return [
        `Runtime status for: ${planLabel}`,
        `Loop state:    ${status.loopState}`,
        `Phase:         ${status.phase}`,
        `Milestone:     ${milestoneLabel}`,
        "",
        "Counters:",
        `  Total attempts:           ${counters.totalAttempts}`,
        `  Total turns:              ${counters.totalTurns} / ${counters.maxTotalTurns}`,
        `  Turns since last outcome: ${counters.turnsSinceLastOutcome}`,
        `  No-progress count:        ${counters.noProgress}`,
        `  Repeated blocker count:   ${counters.repeatedBlocker}`,
        `  Verification failures:    ${counters.verificationFailures}`,
        "",
        `Recommended action: ${nextAction}`,
        `Last blocker:       ${lastBlocker}`,
        `Last verification:  ${lastVerification}`,
      ].join("\n");
    }
  };
}

const VAULT_PREFIX = "vault/";
const ISO_DATE_LENGTH = 10;

function buildVaultWriteTool() {
  return {
    description: "Append a dated section to a vault file. Path must be under vault/. Creates the file if it does not exist. Existing content is never overwritten 窶・each call adds a new dated block at the end.",
    args: {
      path: pluginZ.string().describe("Relative path under vault/ (e.g. vault/plans/my-plan/context.md)"),
      content: pluginZ.string().describe("Content to append as a new dated section"),
    },
    execute: async (args: { path: string; content: string }): Promise<string> => {
      const { path: vaultPath, content } = args;
      if (!vaultPath.startsWith(VAULT_PREFIX)) {
        return `Invalid path: vault writes must target paths under vault/. Received: ${vaultPath}`;
      }
      const fullPath = path.resolve(process.cwd(), vaultPath);
      const vaultRoot = path.resolve(process.cwd(), VAULT_PREFIX);
      if (!fullPath.startsWith(vaultRoot + path.sep)) {
        return `Invalid path: resolved path escapes vault/ root. Received: ${vaultPath}`;
      }
      const today = new Date().toISOString().slice(0, ISO_DATE_LENGTH);
      const datedBlock = `_Dated: ${today}_\n\n${content}`;
      let existing = "";
      try {
        existing = await fs.readFile(fullPath, "utf-8");
      } catch (err) {
        if ((err as NodeJS.ErrnoException).code !== "ENOENT") {
          return `Write failed: ${(err as Error).message}`;
        }
      }
      const combined = existing.length > 0 ? `${existing}\n\n${datedBlock}` : datedBlock;
      try {
        await fs.writeFile(fullPath, combined, "utf-8");
      } catch (err) {
        return `Write failed: ${(err as Error).message}`;
      }
      return `Written to ${vaultPath} (${datedBlock.length} bytes appended).`;
    }
  };
}

function buildPlanApproveTool(manager: SessionManager) {
  return {
    description: "Atomically transition the bound plan from status: planning to status: in-progress. Validates that the plan doc contains a ## Milestones section before approving. Use this as the final planner act after all milestones are defined and reviewed.",
    args: {},
    execute: async (_args: Record<string, never>, toolContext: ToolContext): Promise<string> => {
      const sessionId = toolContext.sessionID;
      const resolvedPath = manager.planBindings.get(sessionId);
      if (!resolvedPath) {
        return "No plan is bound to this session. Call hf_plan_start to bind one before approving.";
      }
      let raw: string;
      try {
        raw = await fs.readFile(resolvedPath, "utf-8");
      } catch (err) {
        return `Read failed: ${(err as Error).message}`;
      }
      if (!raw.includes("## Milestones")) {
        return "Plan doc is missing a ## Milestones section. Cannot approve a malformed plan.";
      }
      const statusPattern = /^status:\s*(planning|in-progress|complete)\s*$/m;
      const statusMatch = statusPattern.exec(raw);
      const currentStatus = statusMatch ? statusMatch[1] : null;
      if (currentStatus !== "planning") {
        return `Plan is already in status '${currentStatus ?? "unknown"}' 窶・nothing to approve. Only plans with status: planning can be approved.`;
      }
      const updated = raw.replace(/^(status:\s*)planning(\s*)$/m, "$1in-progress$2");
      try {
        await fs.writeFile(resolvedPath, updated, "utf-8");
      } catch (err) {
        return `Write failed: ${(err as Error).message}`;
      }
      hfLog({ tag: "plugin", msg: "hf_plan_approve: plan approved", data: { sessionId, resolvedPath } });
      return `Plan approved: ${resolvedPath}\nStatus updated from planning 竊・in-progress. The plan is now ready for builder execution.`;
    }
  };
}

export function createPluginTools(context: OpenCodePluginContext, manager: SessionManager): Record<string, unknown> {
  return {
    hf_plan_start: buildPlanStartTool(manager),
    hf_search: buildSearchTool(context, manager),
    hf_plan_complete: buildPlanCompleteTool(manager),
    hf_plan_status: buildPlanStatusTool(manager),
    hf_plan_list: buildPlanListTool(manager),
    hf_plan_unbind: buildPlanUnbindTool(manager),
    hf_runtime_status: buildRuntimeStatusTool(manager),
    hf_vault_write: buildVaultWriteTool(),
    hf_plan_approve: buildPlanApproveTool(manager),
  };
}

/** Minimum body-text length for a section to stand alone. */
export const MIN_BODY_CHARS = 20;

/** Normalise path separators to forward slashes for cross-platform stability. */
export function normalizePath(filePath: string): string {
  return filePath.replaceAll("\\", "/");
}

/**
 * Build a deterministic, human-readable chunk id from a file path and section title.
 * Path separators are normalised to forward slashes for cross-platform stability.
 */
export function makeChunkId(filePath: string, sectionTitle: string): string {
  return `${normalizePath(filePath)}#${sectionTitle}`;
}

/** Options for {@link splitOversized}. */
export interface SplitOversizedOpts {
  /** Regex or string to split on (e.g. `\n\n` for paragraphs, `\n` for lines). Defaults to `/\n\n/`. */
  delimiter?: string | RegExp;
  /** String used to rejoin segments (should match the delimiter). Defaults to `"\n\n"`. */
  rejoin?: string;
}

/**
 * Split text that exceeds maxChars at the given delimiter boundary.
 * Falls back to hard-splitting at maxChars if a single segment is still too long.
 */
export function splitOversized(
  text: string,
  maxChars: number,
  opts?: SplitOversizedOpts,
): string[] {
  const { delimiter = /\n\n/, rejoin = "\n\n" } = opts ?? {};
  if (text.length <= maxChars) return [text];

  const segments = text.split(delimiter);
  const parts: string[] = [];
  let current = "";

  for (const segment of segments) {
    const candidate = current ? `${current}${rejoin}${segment}` : segment;
    if (candidate.length > maxChars && current) {
      parts.push(current);
      current = segment;
    } else {
      current = candidate;
    }
  }

  if (current) {
    parts.push(current);
  }

  // Handle single segments that are still too long
  const result: string[] = [];
  for (const part of parts) {
    if (part.length <= maxChars) {
      result.push(part);
    } else {
      for (let i = 0; i < part.length; i += maxChars) {
        result.push(part.slice(i, i + maxChars));
      }
    }
  }

  return result;
}

export interface NamedChunk {
  name: string;
  text: string;
}

/**
 * Merge chunks whose trimmed text is shorter than MIN_BODY_CHARS with an
 * adjacent chunk.  Short chunks merge forward into the next chunk when one
 * exists, otherwise backward into the previous merged chunk.
 *
 * The separator string is placed between the merged texts (default `"\n\n"`).
 */
export function mergeThinChunks(
  chunks: NamedChunk[],
  separator = "\n\n",
): NamedChunk[] {
  if (chunks.length <= 1) return chunks;

  // Shallow-copy so we can safely mutate the look-ahead slot.
  const input = chunks.map((c) => ({ ...c }));
  const merged: NamedChunk[] = [];

  for (let i = 0; i < input.length; i++) {
    const chunk = input[i]!;

    if (merged.length > 0 && chunk.text.trim().length < MIN_BODY_CHARS) {
      const next = input[i + 1];
      if (next) {
        input[i + 1] = {
          name: chunk.name || next.name,
          text: `${chunk.text}${separator}${next.text}`,
        };
        continue;
      }

      const previous = merged[merged.length - 1]!;
      previous.text = `${previous.text}${separator}${chunk.text}`;
      continue;
    }

    merged.push({ ...chunk });
  }

  return merged;
}

import ts from "typescript";

import type { VaultChunk } from "./types.js";
import { makeChunkId, mergeThinChunks, normalizePath, splitOversized, type NamedChunk } from "./chunk-utils.js";

function getNodeText(sourceText: string, node: ts.Node): string {
  return sourceText.slice(node.getFullStart(), node.getEnd());
}

function createVaultChunk(filePath: string, chunk: { name: string; text: string }): VaultChunk {
  const normalizedPath = normalizePath(filePath);
  return {
    id: makeChunkId(filePath, chunk.name),
    text: chunk.text,
    metadata: {
      sourcePath: filePath,
      sectionTitle: chunk.name,
      documentTitle: normalizedPath,
      kind: "code",
    },
  };
}

function isExported(node: ts.Node): boolean {
  if (!ts.canHaveModifiers(node)) return false;
  return !!ts
    .getModifiers(node)
    ?.some((modifier: ts.Modifier) => modifier.kind === ts.SyntaxKind.ExportKeyword);
}

function declarationName(
  node:
    | ts.FunctionDeclaration
    | ts.ClassDeclaration
    | ts.InterfaceDeclaration
    | ts.TypeAliasDeclaration
    | ts.EnumDeclaration,
): string | null {
  if (node.name) return node.name.text;
  if (isExported(node)) return "default";
  return null;
}

function splitOversizedCode(text: string, maxChars: number): string[] {
  return splitOversized(text, maxChars, { delimiter: "\n", rejoin: "\n" });
}

interface ClassifiedStatements {
  imports: string[];
  catchAll: string[];
  declarations: NamedChunk[];
}

function classifyStatements(
  sourceText: string,
  statements: ReadonlyArray<ts.Statement>,
  sourceFile: ts.SourceFile,
): ClassifiedStatements {
  const imports: string[] = [];
  const catchAll: string[] = [];
  const declarations: NamedChunk[] = [];

  for (const statement of statements) {
    if (
      ts.isImportDeclaration(statement) ||
      ts.isImportEqualsDeclaration(statement) ||
      ts.isExportDeclaration(statement) ||
      ts.isExportAssignment(statement)
    ) {
      imports.push(getNodeText(sourceText, statement));
      continue;
    }

    if (ts.isFunctionDeclaration(statement) || ts.isClassDeclaration(statement)) {
      const name = declarationName(statement);
      if (name) {
        declarations.push({ name, text: getNodeText(sourceText, statement) });
        continue;
      }
    }

    if (
      ts.isInterfaceDeclaration(statement) ||
      ts.isTypeAliasDeclaration(statement) ||
      ts.isEnumDeclaration(statement)
    ) {
      declarations.push({ name: statement.name.text, text: getNodeText(sourceText, statement) });
      continue;
    }

    if (ts.isVariableStatement(statement) && isExported(statement)) {
      const statementText = getNodeText(sourceText, statement);
      for (const declaration of statement.declarationList.declarations) {
        declarations.push({ name: declaration.name.getText(sourceFile), text: statementText });
      }
      continue;
    }

    catchAll.push(getNodeText(sourceText, statement));
  }

  return { imports, catchAll, declarations };
}

function assembleChunks(filePath: string, classified: ClassifiedStatements, maxChunkChars: number | undefined): VaultChunk[] {
  const rawChunks: NamedChunk[] = [];

  if (classified.imports.length > 0) {
    rawChunks.push({ name: "imports", text: classified.imports.join("\n") });
  }

  rawChunks.push(...classified.declarations);

  if (classified.catchAll.length > 0) {
    rawChunks.push({ name: "catch-all", text: classified.catchAll.join("\n") });
  }

  const merged = mergeThinChunks(rawChunks);
  const result: VaultChunk[] = [];

  for (const chunk of merged) {
    if (maxChunkChars && chunk.text.length > maxChunkChars) {
      const parts = splitOversizedCode(chunk.text, maxChunkChars);
      for (let i = 0; i < parts.length; i++) {
        const base = createVaultChunk(filePath, { name: chunk.name, text: parts[i]! });
        base.id = `${base.id}:${i}`;
        result.push(base);
      }
    } else {
      result.push(createVaultChunk(filePath, chunk));
    }
  }

  return result;
}

export function chunkTypeScriptFile(
  filePath: string,
  sourceText: string,
  maxChunkChars?: number,
): VaultChunk[] {
  if (!sourceText.trim()) return [];

  const sourceFile = ts.createSourceFile(filePath, sourceText, ts.ScriptTarget.Latest, true);
  const classified = classifyStatements(sourceText, sourceFile.statements, sourceFile);
  return assembleChunks(filePath, classified, maxChunkChars);
}

import { readEventLines, readStatus, getRuntimePaths } from "./persistence.js";
import { parsePlan } from "./plan-doc.js";
import type { ParsedPlan } from "./types.js";

export interface DoctorResult {
  ok: boolean;
  issues: string[];
}

export async function runDoctor(planPath: string): Promise<DoctorResult> {
  const issues: string[] = [];
  let plan: ParsedPlan;

  try {
    plan = await parsePlan(planPath);
  } catch (error) {
    return {
      ok: false,
      issues: [(error as Error).message]
    };
  }

  const runtimePaths = getRuntimePaths(plan);
  let status = null;
  try {
    status = await readStatus(runtimePaths);
  } catch (error) {
    issues.push((error as Error).message);
  }
  const eventLines = await readEventLines(runtimePaths);

  if (status) {
    if (status.planPath !== plan.path) {
      issues.push("status.json planPath does not match the requested plan path.");
    }

    const expectedCurrentMilestone = plan.currentMilestone?.index ?? null;
    const actualCurrentMilestone = status.currentMilestone?.index ?? null;
    if (expectedCurrentMilestone !== actualCurrentMilestone) {
      issues.push("status.json current milestone is out of sync with the plan doc.");
    }
  } else {
    issues.push("status.json is missing. Hydrate the runtime before using doctor.");
  }

  for (const [index, line] of eventLines.entries()) {
    try {
      JSON.parse(line);
    } catch {
      issues.push(`events.jsonl line ${index + 1} is not valid JSON.`);
      break;
    }
  }

  return {
    ok: issues.length === 0,
    issues
  };
}

import path from "node:path";
import { existsSync, promises as fs, readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";

import type { ExternalIndexConfig, IndexCodeConfig, IndexConfig, ParsedPlan, RuntimeEvent, RuntimeStatus, VaultContext, VaultDocument, VaultPaths } from "./types.js";
import { validateTurnOutcome } from "./turn-outcome-trailer.js";
import { isRecord, isString, isNumber, isBoolean } from "./utils.js";
import { hfLog } from "./logger.js";

const STATUS_FILENAME = "status.json";

function resolvePackageRoot(startDir: string): string {
  let currentDir = startDir;

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- intentional traversal loop with explicit return/throw
  while (true) {
    if (existsSync(path.join(currentDir, "package.json"))) {
      return currentDir;
    }

    const parentDir = path.dirname(currentDir);
    if (parentDir === currentDir) {
      throw new Error(`Unable to resolve package root from ${startDir}`);
    }
    currentDir = parentDir;
  }
}

function loadDefaultIndexConfig(): IndexConfig {
  const moduleDir = path.dirname(fileURLToPath(import.meta.url));
  const packageRoot = resolvePackageRoot(moduleDir);
  const configPath = path.join(packageRoot, "schemas", "index-defaults.json");
  return JSON.parse(readFileSync(configPath, "utf8")) as IndexConfig;
}

export const DEFAULT_INDEX_CONFIG: IndexConfig = loadDefaultIndexConfig();

function mergeCodeConfig(defaults: IndexCodeConfig, raw: unknown): IndexCodeConfig {
  if (!isRecord(raw)) return defaults;
  return {
    enabled: isBoolean(raw.enabled) ? raw.enabled : defaults.enabled,
    roots: Array.isArray(raw.roots) && raw.roots.every(isString) ? raw.roots : defaults.roots,
    extensions: Array.isArray(raw.extensions) && raw.extensions.every(isString) ? raw.extensions : defaults.extensions,
    exclude: Array.isArray(raw.exclude) && raw.exclude.every(isString) ? raw.exclude : defaults.exclude,
  };
}

function mergeExternalConfig(defaults: ExternalIndexConfig | undefined, raw: unknown): ExternalIndexConfig | undefined {
  if (!isRecord(raw)) return defaults;
  const roots = Array.isArray(raw.roots) && raw.roots.every(isString) ? raw.roots : (defaults?.roots ?? []);
  const rawExts = Array.isArray(raw.extensions) && raw.extensions.every(isString) ? raw.extensions : undefined;
  const extensions = rawExts ?? defaults?.extensions;
  const rawExclude = Array.isArray(raw.exclude) && raw.exclude.every(isString) ? raw.exclude : undefined;
  const exclude = rawExclude ?? defaults?.exclude;
  return {
    roots,
    ...(extensions ? { extensions } : {}),
    ...(exclude ? { exclude } : {}),
  };
}

function safeNumber(value: unknown, fallback: number): number {
  return isNumber(value) && value > 0 ? value : fallback;
}

export async function loadIndexConfig(repoRoot: string): Promise<IndexConfig> {
  const configPath = path.join(repoRoot, "hybrid-framework.json");
  try {
    const raw = await fs.readFile(configPath, "utf8");
    const parsed = JSON.parse(raw);
    if (!isRecord(parsed) || !isRecord(parsed.index)) {
      return { ...DEFAULT_INDEX_CONFIG };
    }
    const idx = parsed.index;
    const externalConfig = mergeExternalConfig(DEFAULT_INDEX_CONFIG.external, idx.external);
    return {
      enabled: isBoolean(idx.enabled) ? idx.enabled : DEFAULT_INDEX_CONFIG.enabled,
      code: mergeCodeConfig(DEFAULT_INDEX_CONFIG.code, idx.code),
      ...(externalConfig ? { external: externalConfig } : {}),
      semanticTopK: safeNumber(idx.semanticTopK, DEFAULT_INDEX_CONFIG.semanticTopK),
      maxChunkChars: safeNumber(idx.maxChunkChars, DEFAULT_INDEX_CONFIG.maxChunkChars),
      embeddingBatchSize: safeNumber(idx.embeddingBatchSize, DEFAULT_INDEX_CONFIG.embeddingBatchSize),
      timeoutMs: safeNumber(idx.timeoutMs, DEFAULT_INDEX_CONFIG.timeoutMs),
      charBudget: safeNumber(idx.charBudget, DEFAULT_INDEX_CONFIG.charBudget),
      planningCharBudget: safeNumber(idx.planningCharBudget, DEFAULT_INDEX_CONFIG.planningCharBudget),
      planningSemanticTopK: safeNumber(idx.planningSemanticTopK, DEFAULT_INDEX_CONFIG.planningSemanticTopK),
    };
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return { ...DEFAULT_INDEX_CONFIG };
    }
    if (error instanceof SyntaxError) {
      hfLog({ tag: "persistence", msg: "loadIndexConfig invalid JSON, using defaults", data: { configPath } });
      return { ...DEFAULT_INDEX_CONFIG };
    }
    throw error;
  }
}

export interface RuntimePaths {
  runtimeDir: string;
  statusPath: string;
  eventsPath: string;
  resumePromptPath: string;
}

const PLAN_VAULT_FILES = [
  { name: "context.md", title: "Plan context" },
  { name: "discoveries.md", title: "Plan discoveries" },
  { name: "decisions.md", title: "Plan decisions" },
  { name: "references.md", title: "Plan references" }
] as const;

const SHARED_VAULT_FILES = [
  { name: "architecture.md", title: "Shared architecture" },
  { name: "patterns.md", title: "Shared patterns" },
  { name: "decisions.md", title: "Shared decisions" }
] as const;

export function getRuntimePaths(plan: ParsedPlan): RuntimePaths {
  const runtimeDir = path.join(path.dirname(plan.path), "runtime", plan.slug);

  return {
    runtimeDir,
    statusPath: path.join(runtimeDir, STATUS_FILENAME),
    eventsPath: path.join(runtimeDir, "events.jsonl"),
    resumePromptPath: path.join(runtimeDir, "resume-prompt.txt")
  };
}

export function getPlanlessRuntimePaths(cwd: string): RuntimePaths {
  const runtimeDir = path.join(cwd, "plans", "runtime", "_planless");

  return {
    runtimeDir,
    statusPath: path.join(runtimeDir, STATUS_FILENAME),
    eventsPath: path.join(runtimeDir, "events.jsonl"),
    resumePromptPath: path.join(runtimeDir, "resume-prompt.txt")
  };
}

export async function ensurePlanlessRuntimeDir(cwd: string): Promise<RuntimePaths> {
  const runtimePaths = getPlanlessRuntimePaths(cwd);
  await fs.mkdir(runtimePaths.runtimeDir, { recursive: true });
  return runtimePaths;
}

export function getRepoRoot(plan?: ParsedPlan, planlessCwd?: string): string {
  if (plan) {
    return path.dirname(path.dirname(plan.path));
  }

  if (planlessCwd) {
    return planlessCwd;
  }

  throw new Error("Repo root requires a parsed plan or a planless cwd.");
}

export function getVaultPaths(plan: ParsedPlan): VaultPaths {
  const plansDir = path.dirname(plan.path);
  const repoRoot = path.dirname(plansDir);
  const vaultRoot = path.join(repoRoot, "vault");
  const planDir = path.join(vaultRoot, "plans", plan.slug);
  const sharedDir = path.join(vaultRoot, "shared");

  return {
    vaultRoot,
    planDir,
    sharedDir,
    planFiles: PLAN_VAULT_FILES.map((file) => path.join(planDir, file.name)),
    sharedFiles: SHARED_VAULT_FILES.map((file) => path.join(sharedDir, file.name))
  };
}

export function getPlanlessVaultPaths(cwd: string): VaultPaths {
  const vaultRoot = path.join(cwd, "vault");
  const sharedDir = path.join(vaultRoot, "shared");

  return {
    vaultRoot,
    planDir: "",
    sharedDir,
    planFiles: [],
    sharedFiles: SHARED_VAULT_FILES.map((file) => path.join(sharedDir, file.name))
  };
}

export async function ensureRuntimeDir(plan: ParsedPlan): Promise<RuntimePaths> {
  const runtimePaths = getRuntimePaths(plan);
  await fs.mkdir(runtimePaths.runtimeDir, { recursive: true });
  return runtimePaths;
}

export async function readStatus(runtimePaths: RuntimePaths): Promise<RuntimeStatus | null> {
  try {
    const raw = await fs.readFile(runtimePaths.statusPath, "utf8");
    let parsed: unknown;
    try {
      parsed = JSON.parse(raw);
    } catch (error) {
      throw new Error(`Invalid runtime status JSON at ${runtimePaths.statusPath}: ${(error as Error).message}`);
    }
    validateRuntimeStatus(parsed, runtimePaths.statusPath);
    return parsed;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return null;
    }
    throw error;
  }
}

export async function writeStatus(runtimePaths: RuntimePaths, status: RuntimeStatus): Promise<void> {
  await fs.writeFile(runtimePaths.statusPath, `${JSON.stringify(status, null, 2)}\n`, "utf8");
}

/**
 * Per-file write queue to prevent concurrent appendFile calls from
 * interleaving partial JSON lines.
 */
const writeQueues = new Map<string, Promise<void>>();

export async function appendEvent(runtimePaths: RuntimePaths, event: RuntimeEvent): Promise<void> {
  const key = runtimePaths.eventsPath;
  const previous = writeQueues.get(key) ?? Promise.resolve();
  const next = previous.then(async () => {
    await fs.appendFile(key, `${JSON.stringify(event)}\n`, "utf8");
  });
  writeQueues.set(key, next.catch((error) => {
    hfLog({ tag: "persistence", msg: "appendEvent write failed", data: { path: key, error: (error as Error).message } });
  }));
  await next;
}

export async function writeResumePrompt(runtimePaths: RuntimePaths, prompt: string): Promise<void> {
  await fs.writeFile(runtimePaths.resumePromptPath, `${prompt.trim()}\n`, "utf8");
}

export async function readEventLines(runtimePaths: RuntimePaths): Promise<string[]> {
  try {
    const raw = await fs.readFile(runtimePaths.eventsPath, "utf8");
    return raw.split(/\r?\n/).filter(Boolean);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return [];
    }
    throw error;
  }
}

export async function readVaultContext(vaultPaths: VaultPaths): Promise<VaultContext> {
  const [plan, shared] = await Promise.all([
    readVaultDocuments(vaultPaths.planFiles, PLAN_VAULT_FILES),
    readVaultDocuments(vaultPaths.sharedFiles, SHARED_VAULT_FILES)
  ]);

  return { plan, shared };
}

async function readVaultDocuments(
  filePaths: string[],
  fileDefs: ReadonlyArray<{ name: string; title: string }>
): Promise<VaultDocument[]> {
  const documents = await Promise.all(filePaths.map(async (filePath, index) => {
    try {
      const content = await fs.readFile(filePath, "utf8");
      const trimmed = content.trim();
      if (!trimmed) {
        return null;
      }

      return {
        path: filePath,
        title: fileDefs[index]?.title ?? path.basename(filePath, path.extname(filePath)),
        content: trimmed
      };
    } catch (error) {
      if ((error as NodeJS.ErrnoException).code === "ENOENT") {
        return null;
      }
      throw error;
    }
  }));

  return documents.filter((document): document is VaultDocument => document !== null);
}

// 笏笏 Compact validation helpers 笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏笏
// Each helper throws with a consistent message format:
//   "Invalid runtime status at <path>: <field> must be <constraint>."

interface ValidationContext {
  prefix: string;
  statusPath: string;
}

function fail(statusPath: string, field: string, constraint: string): never {
  throw new Error(`Invalid runtime status at ${statusPath}: ${field} must be ${constraint}.`);
}

// eslint-disable-next-line no-restricted-syntax -- expectString is itself a type assertion helper; typeof is unavoidable here
function expectString(v: unknown, f: string, p: string): asserts v is string { if (typeof v !== "string") fail(p, f, "a string"); }
// eslint-disable-next-line no-restricted-syntax -- expectNumber is itself a type assertion helper; typeof is unavoidable here
function expectNumber(v: unknown, f: string, p: string): asserts v is number { if (typeof v !== "number" || Number.isNaN(v)) fail(p, f, "a number"); }
// eslint-disable-next-line no-restricted-syntax -- expectBoolean is itself a type assertion helper; typeof is unavoidable here
function expectBoolean(v: unknown, f: string, p: string): asserts v is boolean { if (typeof v !== "boolean") fail(p, f, "a boolean"); }

function expectEnum(v: unknown, allowed: readonly string[], ctx: ValidationContext): void {
  // eslint-disable-next-line no-restricted-syntax -- expectEnum checks for string type as part of enum validation; typeof is unavoidable here
  if (typeof v !== "string" || !allowed.includes(v)) fail(ctx.statusPath, ctx.prefix, `one of ${allowed.join(", ")}`);
}

function expectObject(v: unknown, f: string, p: string): asserts v is Record<string, unknown> {
  if (!isRecord(v)) fail(p, f, "an object");
}

/** Validate a flat record where every listed key must be a certain type. */
function expectFields(
  obj: Record<string, unknown>,
  fields: Record<string, "string" | "number" | "boolean">,
  ctx: ValidationContext,
): void {
  for (const [key, type] of Object.entries(fields)) {
    const fq = ctx.prefix ? `${ctx.prefix}.${key}` : key;
    if (type === "string") expectString(obj[key], fq, ctx.statusPath);
    else if (type === "number") expectNumber(obj[key], fq, ctx.statusPath);
    else expectBoolean(obj[key], fq, ctx.statusPath);
  }
}

/** Validate a field only if it's present (not undefined). */
function optionalString(obj: Record<string, unknown>, key: string, ctx: ValidationContext): void {
  if (obj[key] !== undefined) expectString(obj[key], `${ctx.prefix}.${key}`, ctx.statusPath);
}

function optionalBoolean(obj: Record<string, unknown>, key: string, ctx: ValidationContext): void {
  if (obj[key] !== undefined) expectBoolean(obj[key], `${ctx.prefix}.${key}`, ctx.statusPath);
}

function validateMilestoneShape(value: Record<string, unknown>, ctx: ValidationContext): void {
  if (value.currentMilestone === null) return;
  expectObject(value.currentMilestone, "currentMilestone", ctx.statusPath);
  expectFields(value.currentMilestone, { index: "number", checked: "boolean", text: "string", title: "string" }, { prefix: "currentMilestone", statusPath: ctx.statusPath });
}

function validateCounters(value: Record<string, unknown>, ctx: ValidationContext): void {
  expectObject(value.counters, "counters", ctx.statusPath);
  const counterFields = ["totalAttempts", "totalTurns", "maxTotalTurns", "noProgress", "repeatedBlocker", "verificationFailures", "turnsSinceLastOutcome"];
  for (const f of counterFields) {
    expectNumber((value.counters)[f], `counters.${f}`, ctx.statusPath);
  }
}

function validateLastOutcome(value: Record<string, unknown>, ctx: ValidationContext): void {
  if (value.lastOutcome === undefined || value.lastOutcome === null) return;
  const issues = validateTurnOutcome(value.lastOutcome);
  if (issues.length > 0) {
    throw new Error(`Invalid runtime status at ${ctx.statusPath}: lastOutcome ${issues[0]?.path} ${issues[0]?.message}`);
  }
}

function validateSubagents(value: Record<string, unknown>, ctx: ValidationContext): void {
  if (!Array.isArray(value.subagents)) fail(ctx.statusPath, "subagents", "an array");
  for (let i = 0; i < (value.subagents as unknown[]).length; i++) {
    const sub = (value.subagents as unknown[])[i];
    const subCtx: ValidationContext = { prefix: `subagents[${i}]`, statusPath: ctx.statusPath };
    expectObject(sub, `subagents[${i}]`, ctx.statusPath);
    expectFields(sub, { id: "string", name: "string", startedAt: "string" }, subCtx);
    expectEnum(sub.status, ["running", "completed", "failed"], { prefix: `subagents[${i}].status`, statusPath: ctx.statusPath });
    optionalString(sub, "completedAt", subCtx);
  }
}

function validateRecovery(value: Record<string, unknown>, ctx: ValidationContext): void {
  if (value.recovery === undefined) return;
  const p = ctx.statusPath;
  expectObject(value.recovery, "recovery", p);
  expectEnum(value.recovery.trigger, ["stop", "idle", "compact", "resume"], { prefix: "recovery.trigger", statusPath: p });
  if (value.recovery.sourceTrigger !== undefined) {
    expectEnum(value.recovery.sourceTrigger, ["stop", "idle", "compact"], { prefix: "recovery.sourceTrigger", statusPath: p });
  }
  expectEnum(value.recovery.vendor, ["opencode", "claude", "runtime"], { prefix: "recovery.vendor", statusPath: p });
  expectFields(value.recovery, { eventType: "string", pendingOutcome: "boolean", at: "string" }, { prefix: "recovery", statusPath: p });
  optionalString(value.recovery, "sessionId", { prefix: "recovery", statusPath: p });
}

function validateRuntimeStatus(value: unknown, statusPath: string): asserts value is RuntimeStatus {
  const p = statusPath;
  expectObject(value, "root", p);

  if (value.version !== 1) fail(p, "version", "1");
  expectFields(value, { planPath: "string", planSlug: "string", planMtimeMs: "number", autoContinue: "boolean", updatedAt: "string" }, { prefix: "", statusPath: p });
  expectEnum(value.loopState, ["idle", "running", "paused", "escalated", "complete"], { prefix: "loopState", statusPath: p });
  expectEnum(value.phase, ["planning", "execution"], { prefix: "phase", statusPath: p });

  validateMilestoneShape(value, { prefix: "", statusPath: p });
  validateCounters(value, { prefix: "", statusPath: p });

  // sessions
  expectObject(value.sessions, "sessions", p);
  for (const [vendor, session] of Object.entries(value.sessions)) {
    if (session === undefined) continue;
    expectObject(session, `sessions.${vendor}`, p);
    expectFields(session, { id: "string", updatedAt: "string" }, { prefix: `sessions.${vendor}`, statusPath: p });
  }

  validateSubagents(value, { prefix: "", statusPath: p });

  // optional top-level strings
  for (const key of ["lastProgressAt", "recommendedNextAction", "lastTurnEvaluatedAt"] as const) {
    optionalString(value, key, { prefix: "", statusPath: p });
  }
  optionalBoolean(value, "awaitingBuilderApproval", { prefix: "", statusPath: p });

  // lastBlocker
  if (value.lastBlocker !== undefined) {
    expectObject(value.lastBlocker, "lastBlocker", p);
    expectFields(value.lastBlocker, { signature: "string", message: "string", at: "string" }, { prefix: "lastBlocker", statusPath: p });
  }

  // lastVerification
  if (value.lastVerification !== undefined) {
    expectObject(value.lastVerification, "lastVerification", p);
    expectEnum(value.lastVerification.status, ["pass", "fail", "unknown"], { prefix: "lastVerification.status", statusPath: p });
    optionalString(value.lastVerification, "summary", { prefix: "lastVerification", statusPath: p });
    expectString(value.lastVerification.at, "lastVerification.at", p);
  }

  validateRecovery(value, { prefix: "", statusPath: p });
  validateLastOutcome(value, { prefix: "", statusPath: p });
}

/**
 * Scan plans/runtime/ for the most recently updated non-complete managed plan.
 * Returns the plan's absolute path, or null if none is active.
 */
export async function resolveLastActivePlanPath(cwd: string): Promise<string | null> {
  const runtimeRoot = path.join(cwd, "plans", "runtime");
  let entries: string[];
  try {
    entries = await fs.readdir(runtimeRoot);
  } catch {
    return null;
  }

  let best: { planPath: string; updatedAt: string } | null = null;
  for (const entry of entries) {
    if (entry === "_planless") continue;
    const statusPath = path.join(runtimeRoot, entry, STATUS_FILENAME);
    try {
      const raw = await fs.readFile(statusPath, "utf8");
      const status = JSON.parse(raw) as { planPath?: string; loopState?: string; updatedAt?: string };
      if (!status.planPath || status.loopState === "complete") continue;
      if (!best || (status.updatedAt && status.updatedAt > best.updatedAt)) {
        best = { planPath: status.planPath, updatedAt: status.updatedAt ?? "" };
      }
    } catch { continue; }
  }
  return best?.planPath ?? null;
}

import path from "node:path";
import { promises as fs } from "node:fs";

import { hfLog } from "./logger.js";
import type { MilestoneContext, ParsedPlan, PlanConfig, PlanMilestone, ReviewPolicy } from "./types.js";

const CHECKBOX_PATTERN = /^- \[([ x])\] (.+)$/;
const METADATA_LINE_PATTERN = /^ {2}- ([^:\s]+):[ \t]*(\S[^\r\n]*)$/;
const _KNOWN_METADATA_KEYS = new Set(["scope", "conventions", "notes", "review"]);
const KNOWN_EVIDENCE_KEYS = new Set(["files", "verification", "review_result", "loop", "completed", "per-item", "skill"]);
const DEFAULT_MAX_TOTAL_TURNS = 50;
const DEFAULT_AUTO_CONTINUE = true;
const PLAN_SLUG_PATTERN = /^\d{4}-\d{2}-\d{2}-(.+)-plan$/;
const FRONTMATTER_PATTERN = /^---\r?\n([\s\S]*?)\r?\n---/;
const MAX_TURNS_PATTERN = /^max_turns:\s*(\d+)/m;
const AUTO_CONTINUE_PATTERN = /^auto_continue:\s*(true|false)/m;
const STATUS_PATTERN = /^status:\s*(planning|in-progress|complete)\s*$/m;
const STATUS_IN_PROGRESS = "in-progress" as const;

export function derivePlanSlug(planPath: string): string {
  const base = path.basename(planPath, path.extname(planPath));
  const match = PLAN_SLUG_PATTERN.exec(base);
  return match?.[1] ?? base;
}

function extractFrontmatter(raw: string): string | null {
  const match = FRONTMATTER_PATTERN.exec(raw);
  return match?.[1] ?? null;
}

function extractConfig(fm: string | null): PlanConfig {
  if (!fm) {
    return { maxTotalTurns: DEFAULT_MAX_TOTAL_TURNS, autoContinue: DEFAULT_AUTO_CONTINUE };
  }

  const maxTurnsMatch = MAX_TURNS_PATTERN.exec(fm);
  const maxTotalTurns = maxTurnsMatch ? parseInt(maxTurnsMatch[1] ?? "", 10) : DEFAULT_MAX_TOTAL_TURNS;

  const autoContinueMatch = AUTO_CONTINUE_PATTERN.exec(fm);
  const autoContinue = autoContinueMatch ? autoContinueMatch[1] === "true" : DEFAULT_AUTO_CONTINUE;

  return {
    maxTotalTurns: Number.isFinite(maxTotalTurns) && maxTotalTurns > 0 ? maxTotalTurns : DEFAULT_MAX_TOTAL_TURNS,
    autoContinue
  };
}

function extractStatus(fm: string | null): "planning" | "in-progress" | "complete" {
  if (!fm) {
    return STATUS_IN_PROGRESS;
  }

  const statusMatch = STATUS_PATTERN.exec(fm);
  const value = statusMatch?.[1];
  return value === "complete" || value === STATUS_IN_PROGRESS || value === "planning" ? value : STATUS_IN_PROGRESS;
}

const REVIEW_POLICY_VALUES = new Set(["required", "auto", "skip"]);

function parseScope(value: string): string[] {
  return value
    .split(",")
    .map((s) => s.trim().replaceAll(/^`|`$/g, ""))
    .filter(Boolean);
}

function parseMetadataLines(
  metadataLines: string[]
): { context?: MilestoneContext; reviewPolicy?: ReviewPolicy } {
  const context: MilestoneContext = {};
  let reviewPolicy: ReviewPolicy | undefined;

  for (const line of metadataLines) {
    const match = METADATA_LINE_PATTERN.exec(line);
    if (!match) continue;

    const key = match[1] ?? "";
    const value = (match[2] ?? "").trim();

    switch (key) {
      case "scope":
        context.scope = parseScope(value);
        break;
      case "conventions":
        context.conventions = value;
        break;
      case "notes":
        context.notes = value;
        break;
      case "review":
        if (REVIEW_POLICY_VALUES.has(value)) {
          reviewPolicy = value as ReviewPolicy;
        }
        // Legacy evidence values are ignored; new evidence uses review_result: key
        break;
      default:
        if (!KNOWN_EVIDENCE_KEYS.has(key)) {
          hfLog({ tag: "plan-doc", msg: `unknown metadata key "${key}" 窶・typo?`, data: { key, value } });
        }
        break;
    }
  }

  const result: { context?: MilestoneContext; reviewPolicy?: ReviewPolicy } = {};

  if (context.scope || context.conventions || context.notes) {
    result.context = context;
  }

  if (reviewPolicy) {
    result.reviewPolicy = reviewPolicy;
  }

  return result;
}

function extractSection(raw: string, heading: string): string | undefined {
  const escapedHeading = heading.replaceAll(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const pattern = new RegExp(`^##\\s+${escapedHeading}\\b\\r?\\n([\\s\\S]*?)(?=^##\\s+|\\Z)`, "im");
  const match = pattern.exec(raw);
  const section = match?.[1]?.trim();
  return section && section.length > 0 ? section : undefined;
}

function extractMilestones(raw: string): PlanMilestone[] {
  const lines = raw.split(/\r?\n/);
  const milestones: PlanMilestone[] = [];

  let inMilestones = false;
  let pendingMetadata: string[] = [];

  function finalizePending(): void {
    if (milestones.length > 0 && pendingMetadata.length > 0) {
      const last = milestones[milestones.length - 1]!;
      const parsed = parseMetadataLines(pendingMetadata);
      if (parsed.context) last.context = parsed.context;
      if (parsed.reviewPolicy) last.reviewPolicy = parsed.reviewPolicy;
    }
    pendingMetadata = [];
  }

  for (const line of lines) {
    if (/^##\s+Milestones\b/i.test(line)) {
      inMilestones = true;
      continue;
    }

    if (inMilestones && /^##\s+/.test(line)) {
      finalizePending();
      break;
    }

    if (!inMilestones) {
      continue;
    }

    const checkboxMatch = CHECKBOX_PATTERN.exec(line);
    if (checkboxMatch) {
      finalizePending();

      const [, checkedMark, rawText] = checkboxMatch;
      const text = (rawText ?? "").trim();
      const title = text.replace(/^\d+\.\s*/, "");

      milestones.push({
        index: milestones.length + 1,
        checked: checkedMark === "x",
        text,
        title
      });
      continue;
    }

    // Collect indented metadata lines for the current milestone
    if (METADATA_LINE_PATTERN.test(line)) {
      pendingMetadata.push(line);
    }
  }

  finalizePending();
  return milestones;
}

export async function parsePlan(planPath: string): Promise<ParsedPlan> {
  const absolutePlanPath = path.resolve(planPath);
  const [raw, stats] = await Promise.all([
    fs.readFile(absolutePlanPath, "utf8"),
    fs.stat(absolutePlanPath)
  ]);
  const fm = extractFrontmatter(raw);
  const userIntent = extractSection(raw, "User Intent");
  const milestones = extractMilestones(raw);
  const config = extractConfig(fm);
  const status = extractStatus(fm);

  if (milestones.length === 0) {
    throw new Error(`Plan doc does not contain a ## Milestones section with checkboxes: ${absolutePlanPath}`);
  }

  const currentMilestone = milestones.find((milestone) => !milestone.checked) ?? null;

  return {
    path: absolutePlanPath,
    slug: derivePlanSlug(absolutePlanPath),
    raw,
    ...(userIntent ? { userIntent } : {}),
    milestones,
    currentMilestone,
    status,
    approved: status !== "planning",
    completed: currentMilestone === null && status === "complete",
    mtimeMs: stats.mtimeMs,
    config
  };
}

import path from "node:path";
import { promises as fs } from "node:fs";

import { parsePlan } from "./plan-doc.js";

/**
 * Re-parse the plan only if the file has been modified since last parse.
 * Returns the cached plan if mtime is unchanged.
 */
async function reParsePlanIfChanged(current: ParsedPlan): Promise<ParsedPlan> {
  const stats = await fs.stat(current.path);
  if (stats.mtimeMs === current.mtimeMs) return current;
  return parsePlan(current.path);
}
import { appendEvent, ensureRuntimeDir, ensurePlanlessRuntimeDir, getPlanlessVaultPaths, getRepoRoot, getVaultPaths, loadIndexConfig, readStatus, readVaultContext, writeResumePrompt, writeStatus } from "./persistence.js";
import { buildPlanlessResumePrompt, buildResumePrompt } from "./prompt.js";
import { warmupEmbeddingModel } from "./vault-embeddings.js";
import { hfLog, hfLogTimed } from "./logger.js";
import {
  REPEATED_BLOCKER_THRESHOLD,
  VERIFICATION_FAILURE_THRESHOLD,
  NO_PROGRESS_THRESHOLD,
  type ContinueDecision,
  type IndexConfig,
  type LoopRuntime,
  type ParsedPlan,
  type RuntimeEvent,
  type RuntimeStatus,
  type SubagentRef,
  type TurnOutcome,
  type VaultContext,
  type VaultSearchResult,
} from "./types.js";
import {
  type UnifiedIndexState,
  type VaultIndexState,
  type QueryIndexOpts,
  queryIndexItems,
  refreshVaultIndex,
} from "./runtime-vault.js";
import {
  applyLoopState,
  applyOutcomePhase,
  applyOutcomeCounters,
  computeDecision,
  detectRecoveryTrigger,
  isExplicitBuilderApprovalEvent,
} from "./runtime-decisions.js";

export { REPEATED_BLOCKER_THRESHOLD, VERIFICATION_FAILURE_THRESHOLD, NO_PROGRESS_THRESHOLD };
export type { DecisionInput } from "./runtime-decisions.js";
export { computeDecision } from "./runtime-decisions.js";

/** Default max turns for planless mode. */
const DEFAULT_PLANLESS_MAX_TURNS = 50;

function nowIso(): string {
  return new Date().toISOString();
}

function defaultStatus(plan: ParsedPlan): RuntimeStatus {
  return {
    version: 1,
    planPath: plan.path,
    planSlug: plan.slug,
    planMtimeMs: plan.mtimeMs,
    loopState: plan.completed ? "complete" : "idle",
    phase: plan.approved ? "execution" : "planning",
    currentMilestone: plan.currentMilestone,
    counters: {
      totalAttempts: 0,
      totalTurns: 0,
      maxTotalTurns: plan.config.maxTotalTurns,
      noProgress: 0,
      repeatedBlocker: 0,
      verificationFailures: 0,
      turnsSinceLastOutcome: 0
    },
    sessions: {},
    subagents: [],
    awaitingBuilderApproval: false,
    autoContinue: plan.config.autoContinue,
    updatedAt: nowIso()
  };
}

export function isManagedPlanUnavailable(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }

  return error.message.startsWith("No plan specified.")
    || error.message.startsWith("Plan doc does not contain a ## Milestones section");
}

export class HybridLoopRuntime implements LoopRuntime {
  private plan: ParsedPlan | null = null;
  private status: RuntimeStatus | null = null;
  private vault: VaultContext | null = null;
  private unifiedIndex: UnifiedIndexState | null = null;
  private vaultSearchResults: VaultSearchResult[] | null = null;
  private planlessCwd: string | null = null;
  private indexConfig: IndexConfig | null = null;
  private promptDirty = true;

  private buildVaultIndexSnapshot(): VaultIndexState {
    return {
      unifiedIndex: this.unifiedIndex,
      vaultSearchResults: this.vaultSearchResults,
      plan: this.plan,
      planlessCwd: this.planlessCwd,
      vault: this.vault,
      indexConfig: this.indexConfig,
      lastIndexError: this.status?.lastIndexError,
    };
  }

  private applyVaultIndexSnapshot(snapshot: VaultIndexState): void {
    this.unifiedIndex = snapshot.unifiedIndex;
    this.vaultSearchResults = snapshot.vaultSearchResults;
    if (this.status) {
      if (snapshot.lastIndexError !== undefined) {
        this.status.lastIndexError = snapshot.lastIndexError;
      } else {
        delete this.status.lastIndexError;
      }
    }
  }

  private async doRefreshVaultIndex(): Promise<void> {
    const snapshot = this.buildVaultIndexSnapshot();
    await refreshVaultIndex(snapshot);
    this.applyVaultIndexSnapshot(snapshot);
  }

  public async hydrate(planRef: string): Promise<RuntimeStatus> {
    const done = hfLogTimed({ tag: "runtime", msg: "hydrate", data: { planRef } });
    const plan = await parsePlan(planRef);
    const runtimePaths = await ensureRuntimeDir(plan);
    const existing = await readStatus(runtimePaths);
    this.plan = plan;
    // Vault context is loaded lazily in decideNext() to keep hydration fast.
    this.vault = null;
    this.unifiedIndex = null;
    this.vaultSearchResults = null;
    this.promptDirty = true;
    const defaults = defaultStatus(plan);
    const baseStatus = existing ?? defaults;

    this.status = {
      ...baseStatus,
      planPath: plan.path,
      planSlug: plan.slug,
      planMtimeMs: plan.mtimeMs,
      phase: plan.approved ? "execution" : "planning",
      currentMilestone: plan.currentMilestone,
      loopState: plan.completed ? "complete" : baseStatus.loopState,
      // Sync config from plan doc on every hydration so edits take effect
      counters: {
        ...defaults.counters,
        ...baseStatus.counters,
        totalAttempts: baseStatus.counters.totalAttempts,
        maxTotalTurns: plan.config.maxTotalTurns
      },
      subagents: baseStatus.subagents,
      awaitingBuilderApproval: plan.approved ? baseStatus.awaitingBuilderApproval ?? false : false,
      autoContinue: plan.config.autoContinue,
      updatedAt: nowIso()
    };

    await this.writeState();

    // Load index config from hybrid-framework.json (or use defaults).
    const repoRoot = getRepoRoot(plan);
    this.indexConfig = await loadIndexConfig(repoRoot);

    // Start loading the ONNX embedding model in the background so it's
    // warm by the time decideNext() actually needs it for vault indexing.
    if (this.indexConfig.enabled) {
      warmupEmbeddingModel();
    }

    done({ plan: plan.slug, phase: this.status.phase });
    return this.status;
  }

  public async hydratePlanless(cwd: string): Promise<RuntimeStatus> {
    this.planlessCwd = cwd;
    this.plan = null;
    this.vault = null;
    this.unifiedIndex = null;
    this.vaultSearchResults = null;

    this.indexConfig = await loadIndexConfig(cwd);

    const runtimePaths = await ensurePlanlessRuntimeDir(cwd);
    const existing = await readStatus(runtimePaths);

    this.status = existing ?? {
      version: 1,
      planPath: "",
      planSlug: "_planless",
      planMtimeMs: 0,
      loopState: "idle",
      phase: "execution",
      currentMilestone: null,
      counters: {
        totalAttempts: 0,
        totalTurns: 0,
        maxTotalTurns: DEFAULT_PLANLESS_MAX_TURNS,
        noProgress: 0,
        repeatedBlocker: 0,
        verificationFailures: 0,
        turnsSinceLastOutcome: 0
      },
      sessions: {},
      subagents: [],
      awaitingBuilderApproval: false,
      autoContinue: false,
      updatedAt: nowIso()
    };

    await writeStatus(runtimePaths, this.status);
    return this.status;
  }

  public isPlanless(): boolean {
    return this.planlessCwd !== null;
  }

  public async recordEvent(event: RuntimeEvent): Promise<RuntimeStatus> {
    const status = this.requireStatus();
    const runtimePaths = this.planlessCwd
      ? await ensurePlanlessRuntimeDir(this.planlessCwd)
      : await ensureRuntimeDir(this.requirePlan());
    const recoveryTrigger = detectRecoveryTrigger(event);

    if (event.sessionId) {
      status.sessions[event.vendor] = { id: event.sessionId, updatedAt: event.timestamp };
    }
    if (recoveryTrigger) {
      const sourceTrigger = status.recovery?.trigger === "resume"
        ? status.recovery.sourceTrigger
        : status.recovery?.trigger;
      status.recovery = {
        trigger: recoveryTrigger,
        ...(recoveryTrigger === "resume" && sourceTrigger
          ? { sourceTrigger }
          : {}),
        vendor: event.vendor,
        eventType: event.type,
        ...(event.sessionId ? { sessionId: event.sessionId } : {}),
        pendingOutcome: status.recovery?.pendingOutcome ?? false,
        at: event.timestamp
      };
      this.promptDirty = true;
    }
    if (status.awaitingBuilderApproval && isExplicitBuilderApprovalEvent(event.type)) {
      status.awaitingBuilderApproval = false;
      status.lastOutcome = null;
      this.promptDirty = true;
    }
    status.updatedAt = nowIso();
    if (status.loopState === "idle") {
      status.loopState = "running";
    }

    await appendEvent(runtimePaths, event);
    await this.writeState();

    return status;
  }

  public async recordOutcomeIngestionIssue(event: RuntimeEvent): Promise<void> {
    await this.recordEvent(event);
  }

  public async evaluateTurn(outcome: TurnOutcome): Promise<RuntimeStatus> {
    const done = hfLogTimed({ tag: "runtime", msg: "evaluateTurn", data: { state: outcome.state } });
    const status = this.requireStatus();
    const previousPhase = status.phase;
    const plan = await reParsePlanIfChanged(this.requirePlan());
    this.plan = plan;
    // Invalidate vault 窶・will be reloaded lazily in decideNext().
    this.resetVaultState();
    this.promptDirty = true;
    const now = nowIso();

    applyOutcomePhase({ status, plan, outcome, previousPhase, now });
    applyOutcomeCounters(status, outcome, now);
    applyLoopState(plan, status, outcome);

    await this.writeState();
    done({ loopState: status.loopState });
    return status;
  }

  public async recordSubagent(ref: SubagentRef): Promise<RuntimeStatus> {
    const status = this.requireStatus();

    const existing = status.subagents.findIndex((s) => s.id === ref.id);
    if (existing >= 0) {
      const previous = status.subagents[existing];
      if (!previous) {
        throw new Error(`Subagent index ${existing} disappeared during update.`);
      }
      status.subagents[existing] = {
        ...previous,
        ...ref,
        startedAt: ref.startedAt || previous.startedAt,
        ...(ref.completedAt ?? previous.completedAt
          ? { completedAt: ref.completedAt ?? previous.completedAt }
          : {})
      };
    } else {
      status.subagents.push(ref);
    }
    status.updatedAt = nowIso();

    await this.writeState();
    return status;
  }

  public async noteStopWithoutOutcome(): Promise<RuntimeStatus> {
    hfLog({ tag: "runtime", msg: "noteStopWithoutOutcome" });
    const status = this.requireStatus();
    const plan = await reParsePlanIfChanged(this.requirePlan());
    this.plan = plan;
    // Invalidate vault 窶・will be reloaded lazily in decideNext().
    this.resetVaultState();
    this.promptDirty = true;

    status.planMtimeMs = plan.mtimeMs;
    status.phase = plan.approved ? "execution" : "planning";
    status.currentMilestone = plan.currentMilestone;
    status.counters.totalAttempts += 1;
    status.counters.turnsSinceLastOutcome += 1;
    if (status.recovery) {
      status.recovery.pendingOutcome = true;
    }
    status.updatedAt = nowIso();

    applyLoopState(plan, status);

    await this.writeState();
    return status;
  }

  public async decideNext(): Promise<ContinueDecision> {
    const status = this.requireStatus();

    if (this.planlessCwd) {
      return this.buildPlanlessDecision();
    }

    const plan = this.requirePlan();
    return this.buildPlannedDecision(plan, status);
  }

  private async buildPlanlessDecision(): Promise<ContinueDecision> {
    hfLog({ tag: "runtime", msg: "decideNext planless" });
    try {
      await this.doRefreshVaultIndex();
    } catch (error) {
      hfLog({ tag: "runtime", msg: "vault index failed (planless)", data: { error: (error as Error).message } });
      this.resetVaultState();
    }

    // Load vault shared context for planless compaction recovery
    if (!this.vault && this.planlessCwd) {
      try {
        const vaultPaths = getPlanlessVaultPaths(this.planlessCwd);
        this.vault = await readVaultContext(vaultPaths);
      } catch (error) {
        hfLog({ tag: "runtime", msg: "vault load failed (planless)", data: { error: (error as Error).message } });
        this.vault = null;
      }
    }

    return {
      action: "allow_stop",
      reason: "No active plan. The runtime is providing guardrails only.",
      resume_prompt: buildPlanlessResumePrompt(this.vault, this.vaultSearchResults, {
        planningCharBudget: this.indexConfig?.planningCharBudget,
      })
    };
  }

  private async buildPlannedDecision(plan: ParsedPlan, status: RuntimeStatus): Promise<ContinueDecision> {
    // Lazy vault loading 窶・only when we actually need a resume prompt
    if (!this.vault) {
      const vaultDone = hfLogTimed({ tag: "runtime", msg: "lazy vault load" });
      try {
        this.vault = await readVaultContext(getVaultPaths(plan));
        await this.doRefreshVaultIndex();
      } catch (error) {
        hfLog({ tag: "runtime", msg: "vault load failed", data: { error: (error as Error).message } });
        this.vault = null;
        this.resetVaultState();
      }
      // Persist the enriched resume prompt now that vault is loaded
      this.promptDirty = true;
      await this.writeState();
      vaultDone({ hasVault: this.vault !== null, hasIndex: this.unifiedIndex !== null });
    }

    const resume_prompt = buildResumePrompt(plan, status, {
      vault: this.vault,
      vaultSearchResults: this.vaultSearchResults,
      budgets: {
        charBudget: this.indexConfig?.charBudget,
        planningCharBudget: this.indexConfig?.planningCharBudget,
      },
    });

    if (status.awaitingBuilderApproval) {
      return {
        action: "allow_stop",
        reason: "The plan is approved. Wait for explicit human approval before starting `hf-builder`.",
        resume_prompt
      };
    }

    const decision = computeDecision({
      approved: plan.approved,
      completed: plan.completed,
      currentMilestone: plan.currentMilestone,
      milestoneCount: plan.milestones.length,
      loopState: status.loopState,
      counters: status.counters,
      lastOutcome: status.lastOutcome,
    });

    return { ...decision, resume_prompt };
  }

  public async writeState(): Promise<void> {
    const status = this.requireStatus();

    if (this.planlessCwd) {
      const runtimePaths = await ensurePlanlessRuntimeDir(this.planlessCwd);
      await writeStatus(runtimePaths, status);
      return;
    }

    const plan = this.requirePlan();
    const runtimePaths = await ensureRuntimeDir(plan);

    if (this.promptDirty) {
      const prompt = buildResumePrompt(plan, status, {
        vault: this.vault,
        vaultSearchResults: this.vaultSearchResults,
        budgets: {
          charBudget: this.indexConfig?.charBudget,
          planningCharBudget: this.indexConfig?.planningCharBudget,
        },
      });
      this.promptDirty = false;

      await Promise.all([
        writeStatus(runtimePaths, status),
        writeResumePrompt(runtimePaths, prompt)
      ]);
    } else {
      await writeStatus(runtimePaths, status);
    }
  }

  public getStatus(): RuntimeStatus {
    return this.requireStatus();
  }

  public getPlan(): ParsedPlan | null {
    return this.plan;
  }

  public getIndexConfig(): IndexConfig | null {
    return this.indexConfig;
  }

  /**
   * Query the in-memory unified index (vault + code) with an arbitrary string.
   * Returns the top-K most relevant chunks, or null if the index cannot be
   * loaded or if embedding fails.
   *
   * If the index has not been built yet for this session, triggers a one-time
   * `refreshVaultIndex()` so callers (e.g. planners, subagents) that run before
   * the first `decideNext()` turn still get results. Safe to call from outside
   * the runtime (e.g., from an OpenCode tool handler).
   */
  public async queryIndex(query: string, topK?: number, sourceFilter?: "vault" | "code"): Promise<VaultSearchResult[] | null> {
    if (!this.unifiedIndex) {
      try {
        await this.doRefreshVaultIndex();
      } catch (error) {
        hfLog({ tag: "runtime", msg: "queryIndex: on-demand index build failed", data: { error: (error as Error).message } });
        return null;
      }
    }

    if (!this.unifiedIndex) {
      return null;
    }

    const opts: QueryIndexOpts = {
      query,
      ...(topK !== undefined ? { topK } : {}),
      ...(sourceFilter !== undefined ? { sourceFilter } : {}),
    };
    return queryIndexItems({ unifiedIndex: this.unifiedIndex, indexConfig: this.indexConfig }, opts);
  }

  private resetVaultState(): void {
    this.vault = null;
    this.unifiedIndex = null;
    this.vaultSearchResults = null;
  }

  private requirePlan(): ParsedPlan {
    if (!this.plan) {
      throw new Error("Runtime has not been hydrated with a plan path.");
    }
    return this.plan;
  }

  private requireStatus(): RuntimeStatus {
    if (!this.status) {
      throw new Error("Runtime has not been hydrated with a plan path.");
    }
    return this.status;
  }
}

export async function resolveManagedPlanPath(cwd: string, explicitPlanPath?: string): Promise<string> {
  if (explicitPlanPath) {
    return path.resolve(cwd, explicitPlanPath);
  }

  throw new Error(
    "No plan specified. Use hf_plan_start tool (OpenCode) or --plan flag (CLI) to target a specific plan."
  );
}

import type { RuntimeEvent, TurnOutcome } from "./types.js";
import { isRecord, isString } from "./utils.js";

export const TURN_OUTCOME_TRAILER_LABEL = "turn_outcome:";

const TRAILER_PATTERN = /(?:^|\r?\n)turn_outcome:\s*\r?\n```json[ \t]*\r?\n((?:[^\r\n]*\r?\n)*(?:[^\r\n]*))\r?\n```\s*$/;
const ALLOWED_STATES = new Set(["progress", "blocked", "milestone_complete", "plan_complete", "needs_review"]);
const ALLOWED_RESULTS = new Set(["pass", "fail", "not_run"]);
const ROOT_KEYS = new Set(["state", "summary", "files_changed", "tests_run", "blocker", "next_action"]);
const TEST_KEYS = new Set(["command", "result", "summary"]);
const BLOCKER_KEYS = new Set(["message", "signature"]);

export const TURN_OUTCOME_TRAILER_FORMAT = [
  "turn_outcome:",
  "```json",
  "{",
  '  "state": "progress",',
  '  "summary": "Brief milestone-scoped outcome.",',
  '  "files_changed": [],',
  '  "tests_run": [],',
  '  "next_action": "Describe the next smallest step."',
  "}",
  "```"
].join("\n");

export interface TurnOutcomeValidationIssue {
  path: string;
  message: string;
}

export type TurnOutcomeTrailerParseResult =
  | {
    kind: "valid";
    source: "trailer" | "raw_json";
    outcome: TurnOutcome;
    rawJson: string;
  }
  | {
    kind: "missing";
    source: "trailer";
    errors: TurnOutcomeValidationIssue[];
  }
  | {
    kind: "invalid";
    source: "trailer" | "raw_json";
    rawJson?: string;
    errors: TurnOutcomeValidationIssue[];
  };

function describeType(value: unknown): string {
  if (value === null) {
    return "null";
  }
  if (Array.isArray(value)) {
    return "array";
  }
  // eslint-disable-next-line no-restricted-syntax -- describeType returns the JS type name as a string; typeof is unavoidable here
  return typeof value;
}

interface UnexpectedKeysSchema {
  keys: Set<string>;
  path: string;
}

function pushUnexpectedKeys(
  issues: TurnOutcomeValidationIssue[],
  value: Record<string, unknown>,
  schema: UnexpectedKeysSchema,
): void {
  for (const key of Object.keys(value)) {
    if (!schema.keys.has(key)) {
      issues.push({ path: schema.path, message: `unexpected property "${key}"` });
    }
  }
}

function validateTestsRun(issues: TurnOutcomeValidationIssue[], testsArray: unknown[]): void {
  testsArray.forEach((test, index) => {
    const testPath = `$.tests_run[${index}]`;
    if (!isRecord(test)) {
      issues.push({ path: testPath, message: `expected object, received ${describeType(test)}` });
      return;
    }
    pushUnexpectedKeys(issues, test, { keys: TEST_KEYS, path: testPath });
    if (!isString(test.command)) {
      issues.push({ path: `${testPath}.command`, message: `expected string, received ${describeType(test.command)}` });
    }
    if (!isString(test.result)) {
      issues.push({ path: `${testPath}.result`, message: `expected string, received ${describeType(test.result)}` });
    } else if (!ALLOWED_RESULTS.has(test.result)) {
      issues.push({ path: `${testPath}.result`, message: `expected one of ${Array.from(ALLOWED_RESULTS).join(", ")}` });
    }
    if (test.summary !== undefined && !isString(test.summary)) {
      issues.push({ path: `${testPath}.summary`, message: `expected string, received ${describeType(test.summary)}` });
    }
  });
}

function validateBlocker(issues: TurnOutcomeValidationIssue[], blocker: unknown): void {
  if (blocker === undefined || blocker === null) return;
  if (!isRecord(blocker)) {
    issues.push({ path: "$.blocker", message: `expected object or null, received ${describeType(blocker)}` });
    return;
  }
  pushUnexpectedKeys(issues, blocker, { keys: BLOCKER_KEYS, path: "$.blocker" });
  if (!isString(blocker.message)) {
    issues.push({ path: "$.blocker.message", message: `expected string, received ${describeType(blocker.message)}` });
  }
  if (blocker.signature !== undefined && !isString(blocker.signature)) {
    issues.push({ path: "$.blocker.signature", message: `expected string, received ${describeType(blocker.signature)}` });
  }
}

function validateNextAction(issues: TurnOutcomeValidationIssue[], value: Record<string, unknown>): void {
  if (!isString(value.next_action)) {
    issues.push({ path: "$.next_action", message: `expected string, received ${describeType(value.next_action)}` });
  } else if (value.next_action.length === 0) {
    issues.push({ path: "$.next_action", message: "must not be empty" });
  }
}

export function validateTurnOutcome(value: unknown): TurnOutcomeValidationIssue[] {
  const issues: TurnOutcomeValidationIssue[] = [];
  if (!isRecord(value)) {
    return [{ path: "$", message: `expected object, received ${describeType(value)}` }];
  }

  pushUnexpectedKeys(issues, value, { keys: ROOT_KEYS, path: "$" });

  if (!isString(value.state)) {
    issues.push({ path: "$.state", message: `expected string, received ${describeType(value.state)}` });
  } else if (!ALLOWED_STATES.has(value.state)) {
    issues.push({ path: "$.state", message: `expected one of ${Array.from(ALLOWED_STATES).join(", ")}` });
  }

  if (!isString(value.summary)) {
    issues.push({ path: "$.summary", message: `expected string, received ${describeType(value.summary)}` });
  } else if (value.summary.length === 0) {
    issues.push({ path: "$.summary", message: "must not be empty" });
  }

  if (!Array.isArray(value.files_changed)) {
    issues.push({ path: "$.files_changed", message: `expected array, received ${describeType(value.files_changed)}` });
  } else {
    value.files_changed.forEach((entry, index) => {
      if (!isString(entry)) {
        issues.push({ path: `$.files_changed[${index}]`, message: `expected string, received ${describeType(entry)}` });
      }
    });
  }

  if (!Array.isArray(value.tests_run)) {
    issues.push({ path: "$.tests_run", message: `expected array, received ${describeType(value.tests_run)}` });
  } else {
    validateTestsRun(issues, value.tests_run);
  }

  validateBlocker(issues, value.blocker);
  validateNextAction(issues, value);

  return issues;
}

function parseOutcomeJson(rawJson: string, source: "trailer" | "raw_json"): TurnOutcomeTrailerParseResult {
  let parsed: unknown;
  try {
    parsed = JSON.parse(rawJson);
  } catch (error) {
    return {
      kind: "invalid",
      source,
      rawJson,
      errors: [{ path: "$", message: `invalid JSON: ${(error as Error).message}` }]
    };
  }

  const errors = validateTurnOutcome(parsed);
  if (errors.length > 0) {
    return {
      kind: "invalid",
      source,
      rawJson,
      errors
    };
  }

  return {
    kind: "valid",
    source,
    outcome: parsed as TurnOutcome,
    rawJson
  };
}

export function extractTurnOutcomeTrailer(text: string): TurnOutcomeTrailerParseResult {
  const match = text.match(TRAILER_PATTERN);
  if (!match) {
    return {
      kind: "missing",
      source: "trailer",
      errors: [{ path: "$", message: "missing final turn_outcome trailer" }]
    };
  }

  const rawJson = match[1]?.trim();
  if (!rawJson) {
    return {
      kind: "invalid",
      source: "trailer",
      errors: [{ path: "$", message: "turn_outcome trailer is empty" }]
    };
  }

  return parseOutcomeJson(rawJson, "trailer");
}

export function parseTurnOutcomeInput(text: string): TurnOutcomeTrailerParseResult {
  const trailerResult = extractTurnOutcomeTrailer(text);
  if (trailerResult.kind !== "missing") {
    return trailerResult;
  }

  const trimmed = text.trim();
  if (!trimmed.startsWith("{")) {
    return trailerResult;
  }

  return parseOutcomeJson(trimmed, "raw_json");
}

export function buildTurnOutcomeIngestionEvent(params: {
  vendor: RuntimeEvent["vendor"];
  sessionId?: string;
  source: string;
  result: Exclude<TurnOutcomeTrailerParseResult, { kind: "valid" }>;
}): RuntimeEvent {
  return {
    vendor: params.vendor,
    type: params.result.kind === "missing"
      ? "turn_outcome.trailer_missing"
      : "turn_outcome.trailer_invalid",
    timestamp: new Date().toISOString(),
    ...(params.sessionId ? { sessionId: params.sessionId } : {}),
    payload: {
      source: params.source,
      parser_source: params.result.source,
      errors: params.result.errors,
      ...(params.result.kind === "invalid" && params.result.rawJson
        ? { raw_json: params.result.rawJson }
        : {})
    }
  };
}

import type { VaultDocument, VaultChunk } from "./types.js";
import { MIN_BODY_CHARS, makeChunkId, splitOversized } from "./chunk-utils.js";

/**
 * Header pattern: lines starting with `## ` or `### `.
 * We deliberately exclude `# ` (top-level) so document titles don't split.
 */
const HEADER_RE = /^#{2,3}\s+/;

interface RawSection {
  /** e.g. "## Context"  (empty string for preamble) */
  headerLine: string;
  bodyLines: string[];
}

/**
 * Extract the section title from a header line.
 * Returns an empty string for preamble (no header).
 */
function extractTitle(headerLine: string): string {
  return headerLine.replace(/^#{2,3}\s+/, "").trim();
}

/**
 * Split a markdown document into raw sections at `##` / `###` boundaries.
 */
function splitIntoRawSections(content: string): RawSection[] {
  const lines = content.split("\n");
  const sections: RawSection[] = [];

  let current: RawSection = { headerLine: "", bodyLines: [] };

  for (const line of lines) {
    if (HEADER_RE.test(line)) {
      // Flush the previous section
      sections.push(current);
      current = { headerLine: line, bodyLines: [] };
    } else {
      current.bodyLines.push(line);
    }
  }
  // Flush last section
  sections.push(current);

  return sections;
}

/**
 * Compute the body text length of a raw section (excluding the header).
 * Only counts non-whitespace meaningful characters.
 */
function bodyTextLength(section: RawSection): number {
  return section.bodyLines.join("\n").trim().length;
}

/**
 * Merge sections whose body text is shorter than MIN_BODY_CHARS with the
 * following section. When the last section is short, merge it with the
 * preceding section instead.
 */
function mergeThinSections(sections: RawSection[]): RawSection[] {
  if (sections.length <= 1) return sections;

  // Build a working copy so we never mutate the input array.
  const input = sections.map((s) => ({ headerLine: s.headerLine, bodyLines: [...s.bodyLines] }));
  const merged: RawSection[] = [];

  for (let i = 0; i < input.length; i++) {
    const section = input[i]!;

    if (merged.length > 0 && bodyTextLength(section) < MIN_BODY_CHARS) {
      const next = input[i + 1];
      if (next) {
        // Merge forward: prepend this section's content onto the next section.
        input[i + 1] = {
          headerLine: section.headerLine || next.headerLine,
          bodyLines: [...section.bodyLines, next.headerLine, ...next.bodyLines],
        };
        continue;
      } else {
        // Last section is short 窶・merge backward into the previous merged section.
        const prev = merged[merged.length - 1]!;
        prev.bodyLines.push(
          ...(section.headerLine ? [section.headerLine] : []),
          ...section.bodyLines,
        );
        continue;
      }
    }

    merged.push(section);
  }

  return merged;
}

/**
 * Assemble the text content for a chunk from a raw section.
 */
function sectionText(section: RawSection): string {
  const parts: string[] = [];
  if (section.headerLine) parts.push(section.headerLine);
  parts.push(...section.bodyLines);
  return parts.join("\n");
}

/**
 * Split a VaultDocument into semantically meaningful chunks at `##` / `###` header
 * boundaries. Sections shorter than 20 characters of body text are merged with
 * adjacent sections. Markdown formatting is preserved.
 *
 * @param document - The vault document to chunk.
 * @returns An array of VaultChunk objects. An empty-content document returns an empty array.
 */
export function chunkVaultDocument(document: VaultDocument, maxChunkChars?: number): VaultChunk[] {
  const { path: filePath, title: documentTitle, content } = document;

  // Empty content 竊・empty array
  if (!content.trim()) return [];

  const rawSections = splitIntoRawSections(content);

  // Filter out empty preamble (no header, no body)
  const nonEmpty = rawSections.filter(
    (s) => s.headerLine || s.bodyLines.join("").trim().length > 0,
  );

  if (nonEmpty.length === 0) return [];

  // If there are no headers at all, return the whole document as one chunk
  const hasHeaders = nonEmpty.some((s) => s.headerLine);
  if (!hasHeaders) {
    const text = content;
    const sectionTitle = documentTitle;
    return [
      {
        id: makeChunkId(filePath, sectionTitle),
        text,
        metadata: { sourcePath: filePath, sectionTitle, documentTitle },
      },
    ];
  }

  // Merge thin sections
  const merged = mergeThinSections(nonEmpty);

  const chunks: VaultChunk[] = [];
  for (const section of merged) {
    const title = section.headerLine
      ? extractTitle(section.headerLine)
      : documentTitle;
    const text = sectionText(section);

    if (maxChunkChars && text.length > maxChunkChars) {
      const parts = splitOversized(text, maxChunkChars);
      for (let i = 0; i < parts.length; i++) {
        chunks.push({
          id: `${makeChunkId(filePath, title)}:${i}`,
          text: parts[i]!,
          metadata: { sourcePath: filePath, sectionTitle: title, documentTitle },
        });
      }
    } else {
      chunks.push({
        id: makeChunkId(filePath, title),
        text,
        metadata: { sourcePath: filePath, sectionTitle: title, documentTitle },
      });
    }
  }

  return chunks;
}
